'use client';

import { cva, type VariantProps } from 'class-variance-authority';
import { Inbox } from 'lucide-react';
import type { ReactNode } from 'react';

import { cn } from '../../utils';

const emptyStateVariants = cva(
  'flex flex-col items-center justify-center px-4 text-center',
  {
    variants: {
      size: {
        sm: 'py-6',
        default: 'py-12',
        lg: 'py-16',
      },
    },
    defaultVariants: {
      size: 'default',
    },
  }
);

const iconSizeClasses = {
  sm: 'h-8 w-8',
  default: 'h-12 w-12',
  lg: 'h-16 w-16',
};

const iconInnerSizeClasses = {
  sm: 'h-4 w-4',
  default: 'h-6 w-6',
  lg: 'h-8 w-8',
};

export interface EmptyStateProps extends VariantProps<typeof emptyStateVariants> {
  /** Icon to display (defaults to Inbox) */
  icon?: ReactNode;
  /** Title text */
  title: string;
  /** Description text */
  description?: string;
  /** Optional action slot (button, link, etc.) */
  action?: ReactNode;
  /** Additional className */
  className?: string;
}

/**
 * EmptyState component for displaying when no data is available.
 *
 * @example
 * ```tsx
 * // Basic usage
 * <EmptyState
 *   title="No results found"
 *   description="Try adjusting your search or filters"
 * />
 *
 * // With action button
 * <EmptyState
 *   title="No projects yet"
 *   description="Create your first project to get started"
 *   action={<Button>Create Project</Button>}
 * />
 *
 * // Custom icon
 * <EmptyState
 *   icon={<FileQuestion className="h-6 w-6" />}
 *   title="No documents"
 * />
 * ```
 */
export function EmptyState({
  icon,
  title,
  description,
  action,
  size = 'default',
  className,
}: EmptyStateProps) {
  const sizeKey = size ?? 'default';

  return (
    <div
      data-slot="empty-state"
      className={cn(emptyStateVariants({ size }), className)}
    >
      <div
        className={cn(
          'mb-4 flex items-center justify-center rounded-full bg-muted text-muted-foreground',
          iconSizeClasses[sizeKey]
        )}
      >
        {icon ?? <Inbox className={iconInnerSizeClasses[sizeKey]} />}
      </div>
      <h3 className="text-lg font-semibold text-foreground">{title}</h3>
      {description && (
        <p className="mt-1 max-w-sm text-sm text-muted-foreground">
          {description}
        </p>
      )}
      {action && <div className="mt-4">{action}</div>}
    </div>
  );
}
