'use client';

import {
  createContext,
  forwardRef,
  useContext,
  type HTMLAttributes,
  type ReactNode,
} from 'react';
import { Check, X, ChevronLeft, ChevronRight, Loader2 } from 'lucide-react';

import { cn } from '../../utils';
import { Button } from './button';

// Context for wizard state
interface WizardContextValue {
  currentStep: number;
  totalSteps: number;
}

const WizardContext = createContext<WizardContextValue | null>(null);

const useWizard = () => {
  const context = useContext(WizardContext);
  if (!context) {
    throw new Error('Wizard components must be used within a Wizard');
  }
  return context;
};

export interface WizardProps extends HTMLAttributes<HTMLDivElement> {
  /** Current step (1-indexed) */
  currentStep: number;
  /** Total number of steps */
  totalSteps: number;
  /** Wizard content */
  children: ReactNode;
}

/**
 * Wizard component for multi-step workflows.
 *
 * @example
 * ```tsx
 * <Wizard currentStep={1} totalSteps={3}>
 *   <WizardHeader title="Create Project" onClose={() => {}} />
 *   <WizardContent>
 *     <p>Step 1 content</p>
 *   </WizardContent>
 *   <WizardFooter
 *     onBack={() => {}}
 *     onNext={() => {}}
 *     isBackDisabled={true}
 *   />
 * </Wizard>
 * ```
 */
const Wizard = forwardRef<HTMLDivElement, WizardProps>(
  ({ currentStep, totalSteps, className, children, ...props }, ref) => (
    <WizardContext.Provider value={{ currentStep, totalSteps }}>
      <div
        ref={ref}
        data-slot="wizard"
        className={cn('flex h-full flex-col', className)}
        {...props}
      >
        {children}
      </div>
    </WizardContext.Provider>
  )
);
Wizard.displayName = 'Wizard';

export interface WizardHeaderProps extends HTMLAttributes<HTMLDivElement> {
  /** Optional title */
  title?: string;
  /** Called when close button is clicked */
  onClose?: () => void;
  /** Show step indicators */
  showStepIndicators?: boolean;
}

const WizardHeader = ({
  title,
  onClose,
  showStepIndicators = true,
  className,
  ...props
}: WizardHeaderProps) => {
  const { currentStep, totalSteps } = useWizard();

  return (
    <div
      data-slot="wizard-header"
      className={cn('flex items-center justify-between border-b px-6 py-4', className)}
      {...props}
    >
      <div className="flex items-center gap-4">
        {title && (
          <h2 className="text-lg font-semibold">{title}</h2>
        )}
        {showStepIndicators && (
          <div className="flex items-center gap-1">
            <span className="text-sm text-muted-foreground">
              Step {currentStep} of {totalSteps}
            </span>
          </div>
        )}
      </div>

      <div className="flex items-center gap-4">
        {showStepIndicators && (
          <div className="flex items-center gap-2">
            {Array.from({ length: totalSteps }, (_, i) => {
              const step = i + 1;
              const isCompleted = step < currentStep;
              const isActive = step === currentStep;

              return (
                <StepIndicator
                  key={step}
                  step={step}
                  isCompleted={isCompleted}
                  isActive={isActive}
                />
              );
            })}
          </div>
        )}

        {onClose && (
          <button
            type="button"
            onClick={onClose}
            className="rounded-sm p-1 opacity-70 ring-offset-background transition-opacity hover:opacity-100 focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2"
            aria-label="Close wizard"
          >
            <X className="h-5 w-5" />
          </button>
        )}
      </div>
    </div>
  );
};
WizardHeader.displayName = 'WizardHeader';

export interface StepIndicatorProps extends HTMLAttributes<HTMLDivElement> {
  /** Step number */
  step: number;
  /** Whether this step is completed */
  isCompleted?: boolean;
  /** Whether this step is active */
  isActive?: boolean;
}

const StepIndicator = ({
  step,
  isCompleted = false,
  isActive = false,
  className,
  ...props
}: StepIndicatorProps) => (
  <div
    data-slot="step-indicator"
    className={cn(
      'flex h-8 w-8 items-center justify-center rounded-full text-sm font-medium transition-colors',
      isCompleted && 'bg-primary text-primary-foreground',
      isActive && 'bg-primary text-primary-foreground ring-2 ring-primary ring-offset-2 ring-offset-background',
      !isCompleted && !isActive && 'bg-muted text-muted-foreground',
      className
    )}
    {...props}
  >
    {isCompleted ? (
      <Check className="h-4 w-4" />
    ) : (
      step
    )}
  </div>
);
StepIndicator.displayName = 'StepIndicator';

export interface WizardContentProps extends HTMLAttributes<HTMLDivElement> {
  children: ReactNode;
}

const WizardContent = ({
  className,
  children,
  ...props
}: WizardContentProps) => (
  <div
    data-slot="wizard-content"
    className={cn('flex-1 overflow-y-auto px-6 py-6', className)}
    {...props}
  >
    {children}
  </div>
);
WizardContent.displayName = 'WizardContent';

export interface WizardFooterProps extends HTMLAttributes<HTMLDivElement> {
  /** Called when back button is clicked */
  onBack?: () => void;
  /** Called when next button is clicked */
  onNext?: () => void;
  /** Called when cancel button is clicked */
  onCancel?: () => void;
  /** Disable back button */
  isBackDisabled?: boolean;
  /** Disable next button */
  isNextDisabled?: boolean;
  /** Show loading state on next button */
  isLoading?: boolean;
  /** Custom label for next button */
  nextLabel?: string;
  /** Custom label for back button */
  backLabel?: string;
  /** Custom label for cancel button */
  cancelLabel?: string;
  /** Show cancel button */
  showCancel?: boolean;
}

const WizardFooter = ({
  onBack,
  onNext,
  onCancel,
  isBackDisabled = false,
  isNextDisabled = false,
  isLoading = false,
  nextLabel = 'Next',
  backLabel = 'Back',
  cancelLabel = 'Cancel',
  showCancel = false,
  className,
  ...props
}: WizardFooterProps) => {
  const { currentStep, totalSteps } = useWizard();
  const isLastStep = currentStep === totalSteps;

  return (
    <div
      data-slot="wizard-footer"
      className={cn(
        'flex items-center justify-between border-t px-6 py-4',
        className
      )}
      {...props}
    >
      <div>
        {showCancel && onCancel && (
          <Button variant="ghost" onClick={onCancel}>
            {cancelLabel}
          </Button>
        )}
      </div>

      <div className="flex items-center gap-2">
        {onBack && (
          <Button
            variant="outline"
            onClick={onBack}
            disabled={isBackDisabled || isLoading}
          >
            <ChevronLeft className="mr-1 h-4 w-4" />
            {backLabel}
          </Button>
        )}

        {onNext && (
          <Button
            onClick={onNext}
            disabled={isNextDisabled || isLoading}
          >
            {isLoading ? (
              <>
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                Loading...
              </>
            ) : (
              <>
                {isLastStep ? 'Finish' : nextLabel}
                {!isLastStep && <ChevronRight className="ml-1 h-4 w-4" />}
              </>
            )}
          </Button>
        )}
      </div>
    </div>
  );
};
WizardFooter.displayName = 'WizardFooter';

export {
  Wizard,
  WizardHeader,
  WizardContent,
  WizardFooter,
  StepIndicator,
  useWizard,
};
