'use client';

import * as React from 'react';
import { format, parse, isValid } from 'date-fns';
import { CalendarIcon } from 'lucide-react';
import { type DateRange } from 'react-day-picker';

import { cn } from '../../utils';
import { Button } from './button';
import { Calendar } from './calendar';
import { Popover, PopoverContent, PopoverTrigger } from './popover';

interface DateRangePickerProps {
  /** Start date in YYYY-MM-DD format */
  from?: string;
  /** End date in YYYY-MM-DD format */
  to?: string;
  /** Callback when start date changes */
  onFromChange: (value: string) => void;
  /** Callback when end date changes */
  onToChange: (value: string) => void;
  /** Placeholder for start date */
  fromPlaceholder?: string;
  /** Placeholder for end date */
  toPlaceholder?: string;
  /** Whether the picker is disabled */
  disabled?: boolean;
  /** Whether the picker has an error */
  hasError?: boolean;
  /** Additional CSS classes */
  className?: string;
}

const DateRangePicker = React.forwardRef<HTMLDivElement, DateRangePickerProps>(
  (
    {
      from,
      to,
      onFromChange,
      onToChange,
      fromPlaceholder = 'Start date',
      toPlaceholder = 'End date',
      disabled = false,
      hasError = false,
      className,
    },
    ref
  ) => {
    const [mounted, setMounted] = React.useState(false);

    // Hydration-safe mounting
    React.useEffect(() => {
      setMounted(true);
    }, []);

    const parseDate = (dateString?: string): Date | undefined => {
      if (!dateString) return undefined;
      const parsed = parse(dateString, 'yyyy-MM-dd', new Date());
      return isValid(parsed) ? parsed : undefined;
    };

    const formatDateString = (date: Date | undefined): string => {
      if (!date) return '';
      return format(date, 'yyyy-MM-dd');
    };

    const fromDate = parseDate(from);
    const toDate = parseDate(to);

    const dateRange: DateRange | undefined =
      fromDate || toDate ? { from: fromDate, to: toDate } : undefined;

    const handleSelect = (range: DateRange | undefined) => {
      onFromChange(formatDateString(range?.from));
      onToChange(formatDateString(range?.to));
    };

    const displayText = React.useMemo(() => {
      if (!fromDate && !toDate) {
        return `${fromPlaceholder} - ${toPlaceholder}`;
      }
      const fromText = fromDate ? format(fromDate, 'MMM d, yyyy') : fromPlaceholder;
      const toText = toDate ? format(toDate, 'MMM d, yyyy') : toPlaceholder;
      return `${fromText} - ${toText}`;
    }, [fromDate, toDate, fromPlaceholder, toPlaceholder]);

    if (!mounted) {
      return (
        <Button
          variant="outline"
          className={cn(
            'w-full justify-start text-left font-normal',
            !from && !to && 'text-muted-foreground',
            hasError && 'border-destructive',
            className
          )}
          disabled={disabled}
        >
          <CalendarIcon className="mr-2 h-4 w-4" />
          <span>{`${fromPlaceholder} - ${toPlaceholder}`}</span>
        </Button>
      );
    }

    return (
      <div ref={ref} className={cn('grid gap-2', className)}>
        <Popover>
          <PopoverTrigger asChild>
            <Button
              variant="outline"
              className={cn(
                'w-full justify-start text-left font-normal',
                !from && !to && 'text-muted-foreground',
                hasError && 'border-destructive'
              )}
              disabled={disabled}
            >
              <CalendarIcon className="mr-2 h-4 w-4" />
              <span>{displayText}</span>
            </Button>
          </PopoverTrigger>
          <PopoverContent
            className="w-auto p-0 [--cell-size:2.5rem]"
            align="start"
          >
            <Calendar
              mode="range"
              defaultMonth={fromDate}
              selected={dateRange}
              onSelect={handleSelect}
              numberOfMonths={2}
              fixedWeeks
            />
          </PopoverContent>
        </Popover>
      </div>
    );
  }
);

DateRangePicker.displayName = 'DateRangePicker';

export { DateRangePicker, type DateRangePickerProps };
