'use client';

import {
  createContext,
  forwardRef,
  useEffect,
  useState,
  type HTMLAttributes,
  type ReactNode,
} from 'react';
import {
  DndContext,
  DragOverlay,
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
  closestCorners,
  type DragEndEvent,
  type DragStartEvent,
} from '@dnd-kit/core';
import {
  SortableContext,
  sortableKeyboardCoordinates,
  useSortable,
  verticalListSortingStrategy,
} from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { GripVertical } from 'lucide-react';

import { cn } from '../../utils';

// Types
export interface KanbanColumn<T> {
  id: string;
  title: string;
  color?: string;
  items: T[];
}

export interface KanbanBoardProps<T extends { id: string }> extends Omit<HTMLAttributes<HTMLDivElement>, 'onDragEnd'> {
  /** Column definitions with items */
  columns: KanbanColumn<T>[];
  /** Called when an item is dropped */
  onDragEnd: (itemId: string, fromColumnId: string, toColumnId: string, newIndex: number) => void;
  /** Render function for card content */
  renderCard: (item: T) => ReactNode;
  /** Optional class for column container */
  columnClassName?: string;
}

// Context for drag state
interface KanbanContextValue<T> {
  activeItem: T | null;
  renderCard: (item: T) => ReactNode;
}

const KanbanContext = createContext<KanbanContextValue<unknown> | null>(null);

/**
 * KanbanBoard component for drag-and-drop column-based layouts.
 *
 * @example
 * ```tsx
 * interface Task {
 *   id: string;
 *   title: string;
 *   assignee: string;
 * }
 *
 * const columns: KanbanColumn<Task>[] = [
 *   { id: 'todo', title: 'To Do', color: 'bg-blue-500', items: [...] },
 *   { id: 'in-progress', title: 'In Progress', color: 'bg-yellow-500', items: [...] },
 *   { id: 'done', title: 'Done', color: 'bg-green-500', items: [...] },
 * ];
 *
 * <KanbanBoard
 *   columns={columns}
 *   onDragEnd={(itemId, from, to, index) => { ... }}
 *   renderCard={(task) => (
 *     <KanbanCard>
 *       <KanbanCardHandle />
 *       <div>{task.title}</div>
 *     </KanbanCard>
 *   )}
 * />
 * ```
 */
function KanbanBoard<T extends { id: string }>({
  columns,
  onDragEnd,
  renderCard,
  className,
  columnClassName,
  ...props
}: KanbanBoardProps<T>) {
  const [mounted, setMounted] = useState(false);
  const [activeItem, setActiveItem] = useState<T | null>(null);

  // Hydration-safe mounting
  useEffect(() => {
    setMounted(true);
  }, []);

  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: {
        distance: 8,
      },
    }),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    })
  );

  const handleDragStart = (event: DragStartEvent) => {
    const { active } = event;
    const activeId = active.id as string;

    // Find the active item
    for (const column of columns) {
      const item = column.items.find((i) => i.id === activeId);
      if (item) {
        setActiveItem(item);
        break;
      }
    }
  };

  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event;
    setActiveItem(null);

    if (!over) return;

    const activeId = active.id as string;
    const overId = over.id as string;

    // Find source column
    let fromColumnId: string | null = null;
    for (const column of columns) {
      if (column.items.some((i) => i.id === activeId)) {
        fromColumnId = column.id;
        break;
      }
    }

    if (!fromColumnId) return;

    // Determine target column and index
    let toColumnId: string | undefined;
    let newIndex: number | undefined;

    // Check if dropped on a column
    const targetColumn = columns.find((c) => c.id === overId);
    if (targetColumn) {
      toColumnId = targetColumn.id;
      newIndex = targetColumn.items.length;
    } else {
      // Dropped on an item - find its column
      for (const column of columns) {
        const itemIndex = column.items.findIndex((i) => i.id === overId);
        if (itemIndex !== -1) {
          toColumnId = column.id;
          newIndex = itemIndex;
          break;
        }
      }
    }

    if (toColumnId !== undefined && newIndex !== undefined) {
      onDragEnd(activeId, fromColumnId, toColumnId, newIndex);
    }
  };

  if (!mounted) {
    // Render static version during SSR
    return (
      <div
        data-slot="kanban-board"
        className={cn('flex gap-4 overflow-x-auto p-4', className)}
        {...props}
      >
        {columns.map((column) => (
          <div
            key={column.id}
            className={cn(
              'flex w-72 flex-shrink-0 flex-col rounded-lg border bg-muted/30',
              columnClassName
            )}
          >
            <div className="flex items-center gap-2 border-b p-3">
              {column.color && (
                <div className={cn('h-3 w-3 rounded-full', column.color)} />
              )}
              <h3 className="font-medium">{column.title}</h3>
              <span className="ml-auto text-sm text-muted-foreground">
                {column.items.length}
              </span>
            </div>
            <div className="flex flex-col gap-2 p-2">
              {column.items.map((item) => (
                <div key={item.id}>{renderCard(item)}</div>
              ))}
            </div>
          </div>
        ))}
      </div>
    );
  }

  return (
    <KanbanContext.Provider value={{ activeItem, renderCard: renderCard as (item: unknown) => ReactNode }}>
      <DndContext
        sensors={sensors}
        collisionDetection={closestCorners}
        onDragStart={handleDragStart}
        onDragEnd={handleDragEnd}
      >
        <div
          data-slot="kanban-board"
          className={cn('flex gap-4 overflow-x-auto p-4', className)}
          {...props}
        >
          {columns.map((column) => (
            <KanbanColumnComponent
              key={column.id}
              column={column}
              renderCard={renderCard}
              className={columnClassName}
            />
          ))}
        </div>

        <DragOverlay>
          {activeItem ? (
            <div className="opacity-80">{renderCard(activeItem)}</div>
          ) : null}
        </DragOverlay>
      </DndContext>
    </KanbanContext.Provider>
  );
}

// Internal column component
interface KanbanColumnComponentProps<T extends { id: string }> {
  column: KanbanColumn<T>;
  renderCard: (item: T) => ReactNode;
  className?: string;
}

function KanbanColumnComponent<T extends { id: string }>({
  column,
  renderCard,
  className,
}: KanbanColumnComponentProps<T>) {
  return (
    <div
      data-slot="kanban-column"
      className={cn(
        'flex w-72 flex-shrink-0 flex-col rounded-lg border bg-muted/30',
        className
      )}
    >
      {/* Column header */}
      <div className="flex items-center gap-2 border-b p-3">
        {column.color && (
          <div className={cn('h-3 w-3 rounded-full', column.color)} />
        )}
        <h3 className="font-medium">{column.title}</h3>
        <span className="ml-auto text-sm text-muted-foreground">
          {column.items.length}
        </span>
      </div>

      {/* Column content */}
      <SortableContext
        items={column.items.map((i) => i.id)}
        strategy={verticalListSortingStrategy}
        id={column.id}
      >
        <div className="flex min-h-[100px] flex-col gap-2 p-2">
          {column.items.map((item) => (
            <SortableItem key={item.id} id={item.id}>
              {renderCard(item)}
            </SortableItem>
          ))}
        </div>
      </SortableContext>
    </div>
  );
}

// Sortable item wrapper
interface SortableItemProps {
  id: string;
  children: ReactNode;
}

function SortableItem({ id, children }: SortableItemProps) {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.5 : 1,
  };

  return (
    <div ref={setNodeRef} style={style} {...attributes} {...listeners}>
      {children}
    </div>
  );
}

export interface KanbanCardProps extends HTMLAttributes<HTMLDivElement> {
  /** Whether the card is being dragged */
  isDragging?: boolean;
  children: ReactNode;
}

/**
 * KanbanCard component for individual items in the board.
 */
const KanbanCard = forwardRef<HTMLDivElement, KanbanCardProps>(
  ({ className, isDragging, children, ...props }, ref) => (
    <div
      ref={ref}
      data-slot="kanban-card"
      className={cn(
        'rounded-md border bg-card p-3 shadow-sm transition-shadow',
        'hover:shadow-md',
        isDragging && 'ring-2 ring-primary shadow-lg',
        className
      )}
      {...props}
    >
      {children}
    </div>
  )
);
KanbanCard.displayName = 'KanbanCard';

export type KanbanCardHandleProps = HTMLAttributes<HTMLDivElement>;

/**
 * KanbanCardHandle component for drag handle indicator.
 */
const KanbanCardHandle = forwardRef<HTMLDivElement, KanbanCardHandleProps>(
  ({ className, ...props }, ref) => (
    <div
      ref={ref}
      data-slot="kanban-card-handle"
      className={cn(
        'cursor-grab text-muted-foreground hover:text-foreground active:cursor-grabbing',
        className
      )}
      {...props}
    >
      <GripVertical className="h-4 w-4" />
    </div>
  )
);
KanbanCardHandle.displayName = 'KanbanCardHandle';

export { KanbanBoard, KanbanCard, KanbanCardHandle };
