'use client';

import { forwardRef, type ComponentPropsWithoutRef } from 'react';
import {
  Circle,
  Loader2,
  Clock,
  CheckCircle2,
  XCircle,
} from 'lucide-react';

import { cn } from '../../utils';

export type StepStatus = 'pending' | 'running' | 'waiting' | 'completed' | 'failed';

export interface StepItem {
  /** Unique identifier for the step */
  id: string;
  /** Display label for the step */
  label: string;
  /** Current status of the step */
  status: StepStatus;
  /** Progress percentage (0-100) when running */
  progress?: number;
  /** Elapsed time in seconds */
  elapsedTime?: number;
}

export interface StepListProps extends ComponentPropsWithoutRef<'nav'> {
  /** Array of steps to display */
  steps: StepItem[];
  /** Currently selected step for viewing output */
  selectedStepId?: string | null;
  /** Callback when step is clicked */
  onStepClick?: (stepId: string) => void;
  /** Title for the step list */
  title?: string;
  /** Whether to show the title */
  showTitle?: boolean;
}

/**
 * Format elapsed time as human-readable string
 */
function formatElapsedTime(seconds: number): string {
  if (seconds < 60) {
    return `${seconds}s`;
  }
  const minutes = Math.floor(seconds / 60);
  const remainingSeconds = seconds % 60;
  if (minutes < 60) {
    return remainingSeconds > 0 ? `${minutes}m ${remainingSeconds}s` : `${minutes}m`;
  }
  const hours = Math.floor(minutes / 60);
  const remainingMinutes = minutes % 60;
  return `${hours}h ${remainingMinutes}m`;
}

/**
 * Get the icon component for a step status
 */
function getStatusIcon(status: StepStatus) {
  switch (status) {
    case 'pending':
      return <Circle className="h-4 w-4 text-muted-foreground" />;
    case 'running':
      return <Loader2 className="h-4 w-4 text-primary animate-spin" />;
    case 'waiting':
      return <Clock className="h-4 w-4 text-amber-500" />;
    case 'completed':
      return <CheckCircle2 className="h-4 w-4 text-green-500" />;
    case 'failed':
      return <XCircle className="h-4 w-4 text-destructive" />;
  }
}

/**
 * StepList - Vertical list of pipeline steps with status indicators
 *
 * Shows all steps in order with their current execution status.
 *
 * @example
 * ```tsx
 * const steps = [
 *   { id: 'seed', label: 'Project Seed', status: 'completed', elapsedTime: 5 },
 *   { id: 'stakeholders', label: 'Stakeholders', status: 'running', progress: 65 },
 *   { id: 'personas', label: 'Persona Drafts', status: 'pending' },
 * ];
 *
 * <StepList
 *   steps={steps}
 *   onStepClick={(id) => setSelectedStep(id)}
 *   selectedStepId={selectedStep}
 * />
 * ```
 */
const StepList = forwardRef<HTMLElement, StepListProps>(
  (
    {
      steps,
      selectedStepId,
      onStepClick,
      title = 'Steps',
      showTitle = true,
      className,
      ...props
    },
    ref
  ) => {
    return (
      <nav
        ref={ref}
        className={cn('space-y-1', className)}
        aria-label="Pipeline steps"
        {...props}
      >
        {showTitle && (
          <h2 className="text-muted-foreground mb-3 px-2 text-xs font-semibold uppercase tracking-wider">
            {title}
          </h2>
        )}

        <ul className="space-y-1" role="list">
          {steps.map((step) => {
            const isSelected = selectedStepId === step.id;
            const isClickable = !!onStepClick;

            return (
              <li key={step.id}>
                <StepItem
                  step={step}
                  isSelected={isSelected}
                  onClick={isClickable ? () => onStepClick(step.id) : undefined}
                />
              </li>
            );
          })}
        </ul>
      </nav>
    );
  }
);

StepList.displayName = 'StepList';

// Step Item Sub-component
interface StepItemProps {
  step: StepItem;
  isSelected?: boolean;
  onClick?: () => void;
}

function StepItem({ step, isSelected, onClick }: StepItemProps) {
  const isRunning = step.status === 'running';
  const isCompleted = step.status === 'completed';
  const isFailed = step.status === 'failed';
  const isWaiting = step.status === 'waiting';

  const statusLabel = isRunning && step.progress !== undefined
    ? `${step.progress}% complete`
    : isCompleted && step.elapsedTime !== undefined
      ? formatElapsedTime(step.elapsedTime)
      : isWaiting
        ? 'Input required'
        : isFailed
          ? 'Error occurred'
          : undefined;

  return (
    <button
      type="button"
      onClick={onClick}
      disabled={!onClick}
      className={cn(
        'w-full flex items-center gap-3 px-2 py-2 rounded-md text-left transition-colors',
        onClick && 'hover:bg-muted/50 cursor-pointer',
        isSelected && 'bg-muted',
        !onClick && 'cursor-default'
      )}
      aria-label={`${step.label}: ${step.status === 'pending' ? 'Not started' : step.status === 'running' ? 'Running' : step.status === 'waiting' ? 'Waiting for input' : step.status === 'completed' ? 'Completed' : 'Failed'}`}
    >
      {/* Status Icon */}
      <span className="flex-shrink-0">{getStatusIcon(step.status)}</span>

      {/* Label and Status */}
      <span className="flex-1 min-w-0">
        <span
          className={cn(
            'block text-sm truncate',
            step.status === 'pending' && 'text-muted-foreground'
          )}
        >
          {step.label}
        </span>
        {statusLabel && (
          <span
            className={cn(
              'block text-xs',
              isRunning && 'text-primary',
              isCompleted && 'text-muted-foreground',
              isFailed && 'text-destructive',
              isWaiting && 'text-amber-500'
            )}
          >
            {statusLabel}
          </span>
        )}
      </span>
    </button>
  );
}

// Step Summary Sub-component
export interface StepSummaryProps extends ComponentPropsWithoutRef<'div'> {
  /** Total number of steps */
  total: number;
  /** Number of completed steps */
  completed: number;
  /** Number of failed steps */
  failed: number;
}

/**
 * Summary of step progress for compact display
 */
const StepSummary = forwardRef<HTMLDivElement, StepSummaryProps>(
  ({ total, completed, failed, className, ...props }, ref) => {
    const pending = total - completed - failed;

    return (
      <div
        ref={ref}
        className={cn('flex items-center gap-3 text-sm', className)}
        {...props}
      >
        <div className="flex items-center gap-1">
          <span className="text-green-600 dark:text-green-400 font-medium">
            {completed}
          </span>
          <span className="text-muted-foreground">done</span>
        </div>
        {pending > 0 && (
          <div className="flex items-center gap-1">
            <span className="font-medium">{pending}</span>
            <span className="text-muted-foreground">pending</span>
          </div>
        )}
        {failed > 0 && (
          <div className="flex items-center gap-1">
            <span className="font-medium text-red-600 dark:text-red-400">
              {failed}
            </span>
            <span className="text-muted-foreground">failed</span>
          </div>
        )}
      </div>
    );
  }
);

StepSummary.displayName = 'StepSummary';

export { StepList, StepSummary };
