'use client';

import { Loader2 } from 'lucide-react';

import { cn } from '../../utils';
import { Skeleton } from './skeleton';

export type LoadingStateVariant = 'spinner' | 'dots' | 'skeleton';
export type LoadingStateSize = 'sm' | 'default' | 'lg';

export interface LoadingStateProps {
  /** Loading variant */
  variant?: LoadingStateVariant;
  /** Optional loading message */
  message?: string;
  /** Size of the loading indicator */
  size?: LoadingStateSize;
  /** Number of skeleton rows (for skeleton variant) */
  rows?: number;
  /** Additional className */
  className?: string;
}

const spinnerSizeClasses = {
  sm: 'h-4 w-4',
  default: 'h-6 w-6',
  lg: 'h-8 w-8',
};

const dotSizeClasses = {
  sm: 'h-1.5 w-1.5',
  default: 'h-2 w-2',
  lg: 'h-2.5 w-2.5',
};

/**
 * LoadingState component for displaying loading indicators.
 *
 * @example
 * ```tsx
 * // Spinner (default)
 * <LoadingState message="Loading..." />
 *
 * // Dots animation
 * <LoadingState variant="dots" />
 *
 * // Skeleton rows
 * <LoadingState variant="skeleton" rows={5} />
 *
 * // Large spinner
 * <LoadingState size="lg" message="Please wait..." />
 * ```
 */
export function LoadingState({
  variant = 'spinner',
  message,
  size = 'default',
  rows = 3,
  className,
}: LoadingStateProps) {
  // Skeleton variant has different layout
  if (variant === 'skeleton') {
    return (
      <div data-slot="loading-state" className={cn('space-y-3', className)}>
        {Array.from({ length: rows }).map((_, i) => (
          <Skeleton key={i} className="h-4 w-full" />
        ))}
      </div>
    );
  }

  return (
    <div
      data-slot="loading-state"
      className={cn(
        'flex flex-col items-center justify-center gap-3 py-8',
        className
      )}
    >
      {variant === 'spinner' && (
        <Loader2
          className={cn('animate-spin text-primary', spinnerSizeClasses[size])}
        />
      )}

      {variant === 'dots' && (
        <div className="flex items-center gap-1">
          {[0, 1, 2].map((i) => (
            <span
              key={i}
              className={cn(
                'animate-pulse rounded-full bg-primary',
                dotSizeClasses[size]
              )}
              style={{ animationDelay: `${i * 150}ms` }}
            />
          ))}
        </div>
      )}

      {message && (
        <span className="text-sm text-muted-foreground">{message}</span>
      )}
    </div>
  );
}

/**
 * PageLoading - convenience component for full-page loading states.
 *
 * @example
 * ```tsx
 * <PageLoading />
 * <PageLoading message="Loading dashboard..." />
 * ```
 */
export function PageLoading({ message = 'Loading...' }: { message?: string }) {
  return (
    <div className="flex min-h-[400px] items-center justify-center">
      <LoadingState variant="spinner" message={message} size="lg" />
    </div>
  );
}
