'use client';

import { forwardRef, memo, useMemo, type ComponentPropsWithoutRef } from 'react';

import { cn } from '../../utils';

export type BinStatus = 'empty' | 'filling' | 'filled';

export interface ProgressBinStripProps
  extends Omit<ComponentPropsWithoutRef<'div'>, 'children'> {
  /** Total number of bins (default: 68) */
  totalBins?: number;
  /** Number of completed bins (0 to totalBins) */
  completedBins: number;
  /** Whether this strip is currently being filled */
  isActive: boolean;
  /** Whether all bins are complete */
  isComplete: boolean;
  /** Whether there was an error */
  hasError?: boolean;
  /** Whether this is linked to existing persona (shows blue instead of orange) */
  isLinked?: boolean;
  /** Number of visual rows (default: 4) */
  rows?: number;
  /** Number of bins per row (default: varies for full width) */
  binsPerRow?: number;
}

// Constants
const DEFAULT_ROWS = 4;
const DEFAULT_BINS_PER_ROW = 50; // Reduced for better visibility

/**
 * Create a 2D grid of bin statuses based on completed count
 * Bins fill left-to-right proportionally to progress
 */
function createBinGrid(
  completedBins: number,
  totalBins: number,
  isActive: boolean,
  isComplete: boolean,
  rows: number,
  binsPerRow: number
): BinStatus[][] {
  // Calculate progress as a percentage (0 to 1)
  const progress = completedBins / totalBins;

  // Calculate how many columns should be filled (all rows fill together)
  const filledColumns = Math.floor(progress * binsPerRow);
  const fillingColumn =
    isActive && !isComplete && filledColumns < binsPerRow ? filledColumns : -1;

  // Initialize grid with appropriate statuses
  const grid: BinStatus[][] = Array.from({ length: rows }, () =>
    Array.from({ length: binsPerRow }, (_, colIndex) => {
      if (colIndex < filledColumns) {
        return 'filled' as BinStatus;
      } else if (colIndex === fillingColumn) {
        return 'filling' as BinStatus;
      }
      return 'empty' as BinStatus;
    })
  );

  return grid;
}

/**
 * Check for reduced motion preference
 */
function usePrefersReducedMotion(): boolean {
  if (typeof window === 'undefined') return false;
  return window.matchMedia?.('(prefers-reduced-motion: reduce)').matches ?? false;
}

/**
 * ProgressBinStrip - Full-width 4-row grid with fill pattern
 *
 * Layout: 4 rows of bins that fill left-to-right
 * Each bin shows fill state with glow effects
 *
 * @example
 * ```tsx
 * // Basic usage
 * <ProgressBinStrip
 *   completedBins={34}
 *   isActive={true}
 *   isComplete={false}
 * />
 *
 * // Linked variant (blue)
 * <ProgressBinStrip
 *   completedBins={68}
 *   isActive={false}
 *   isComplete={true}
 *   isLinked
 * />
 *
 * // Error state
 * <ProgressBinStrip
 *   completedBins={20}
 *   isActive={false}
 *   isComplete={false}
 *   hasError
 * />
 * ```
 */
const ProgressBinStrip = forwardRef<HTMLDivElement, ProgressBinStripProps>(
  (
    {
      totalBins = 68,
      completedBins,
      isActive,
      isComplete,
      hasError = false,
      isLinked = false,
      rows = DEFAULT_ROWS,
      binsPerRow = DEFAULT_BINS_PER_ROW,
      className,
      ...props
    },
    ref
  ) => {
    const prefersReducedMotion = usePrefersReducedMotion();

    // Generate 2D bin grid with statuses
    const binGrid = useMemo(
      () =>
        createBinGrid(
          completedBins,
          totalBins,
          isActive,
          isComplete,
          rows,
          binsPerRow
        ),
      [completedBins, totalBins, isActive, isComplete, rows, binsPerRow]
    );

    // Calculate progress percentage for ARIA
    const progressPercent = Math.round((completedBins / totalBins) * 100);

    // Reduced motion: show simple progress bar
    if (prefersReducedMotion) {
      return (
        <div
          ref={ref}
          role="progressbar"
          aria-valuenow={progressPercent}
          aria-valuemin={0}
          aria-valuemax={100}
          aria-label={`${progressPercent}% complete (${completedBins} of ${totalBins} items)`}
          className={cn(
            'h-6 flex-1 overflow-hidden rounded-sm bg-muted/30',
            className
          )}
          {...props}
        >
          <div
            className={cn(
              'h-full transition-[width] duration-300 ease-out',
              hasError
                ? 'bg-destructive'
                : isLinked
                  ? 'bg-blue-500'
                  : 'bg-primary'
            )}
            style={{ width: `${progressPercent}%` }}
          />
        </div>
      );
    }

    return (
      <div
        ref={ref}
        role="progressbar"
        aria-valuenow={progressPercent}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-label={`${progressPercent}% complete (${completedBins} of ${totalBins} items)`}
        className={cn(
          'relative flex flex-col gap-[2px]',
          // Error state: muted appearance
          hasError && 'opacity-60',
          className
        )}
        {...props}
      >
        {binGrid.map((row, rowIndex) => (
          <div
            key={rowIndex}
            className="relative z-10 flex gap-[2px] overflow-hidden"
          >
            {row.map((status, colIndex) => (
              <Bin
                key={`${rowIndex}-${colIndex}`}
                status={status}
                hasError={hasError}
                isLinked={isLinked}
              />
            ))}
          </div>
        ))}
      </div>
    );
  }
);

ProgressBinStrip.displayName = 'ProgressBinStrip';

// Bin Sub-component
interface BinProps {
  status: BinStatus;
  hasError: boolean;
  isLinked: boolean;
}

const Bin = memo(function Bin({ status, hasError, isLinked }: BinProps) {
  return (
    <div
      className={cn(
        'size-1 shrink-0 rounded-[1px] transition-all duration-150',
        // Empty state
        status === 'empty' && 'bg-[var(--progress-bin-empty)]',
        // Normal generation (orange)
        status === 'filled' &&
          !hasError &&
          !isLinked &&
          'bg-primary shadow-[0_0_6px_rgba(253,91,11,0.6)]',
        status === 'filling' &&
          !hasError &&
          !isLinked &&
          'bg-primary/80 shadow-[0_0_8px_rgba(253,91,11,0.8)] animate-pulse',
        // Linked existing persona (blue)
        status === 'filled' &&
          !hasError &&
          isLinked &&
          'bg-blue-500 shadow-[0_0_6px_rgba(59,130,246,0.6)]',
        status === 'filling' &&
          !hasError &&
          isLinked &&
          'bg-blue-500/80 shadow-[0_0_8px_rgba(59,130,246,0.8)] animate-pulse',
        // Error state
        hasError &&
          status === 'filled' &&
          'bg-destructive/60 shadow-[0_0_6px_rgba(239,68,68,0.6)]',
        hasError &&
          status === 'filling' &&
          'bg-destructive/80 shadow-[0_0_8px_rgba(239,68,68,0.8)]'
      )}
      aria-hidden="true"
    />
  );
});

export { ProgressBinStrip };
