'use client';

import { cva, type VariantProps } from 'class-variance-authority';
import { Minus, TrendingDown, TrendingUp } from 'lucide-react';
import { forwardRef, useMemo, type ComponentPropsWithoutRef, type ReactNode } from 'react';

import { cn, calculateChange, formatNumber, formatCurrency, formatPercent } from '../../utils';
import { Skeleton } from './skeleton';
import { Sparkline } from './sparkline';

export type KpiValueFormat = 'number' | 'currency' | 'percentage';
export type KpiSize = 'sm' | 'md' | 'lg';

export interface KpiCardProps
  extends Omit<ComponentPropsWithoutRef<'article'>, 'children'>,
    VariantProps<typeof kpiCardVariants> {
  /** Label describing the KPI */
  label: string;
  /** Current value (displayed prominently) */
  value: string | number;
  /** Previous value for comparison (calculates change automatically) */
  previousValue?: number;
  /** Change percentage (explicit, overrides calculation from previousValue) */
  change?: number;
  /** Format for displaying the value */
  valueFormat?: KpiValueFormat;
  /** Locale for number formatting */
  locale?: string;
  /** Whether higher values are better (affects color coding) */
  higherIsBetter?: boolean;
  /** Icon to display */
  icon?: ReactNode;
  /** Historical data for sparkline */
  sparklineData?: number[];
  /** Size variant */
  size?: KpiSize;
  /** Visual emphasis with glow effect */
  glow?: boolean;
  /** Loading state */
  loading?: boolean;
}

const kpiCardVariants = cva(
  'bg-card text-card-foreground relative flex flex-col rounded-xl border shadow-sm transition-shadow hover:shadow-md',
  {
    variants: {
      size: {
        sm: 'gap-2 p-3',
        md: 'gap-3 p-4',
        lg: 'gap-4 p-5',
      },
      glow: {
        true: '',
        false: '',
      },
    },
    compoundVariants: [
      {
        glow: true,
        className: 'shadow-[0_0_20px_var(--primary)/0.15]',
      },
    ],
    defaultVariants: {
      size: 'md',
      glow: false,
    },
  }
);

/**
 * Format value based on format type.
 */
function formatValue(
  value: string | number,
  format: KpiValueFormat,
  locale: string
): string {
  if (typeof value === 'string') return value;

  switch (format) {
    case 'currency':
      return formatCurrency(value, { locale });
    case 'percentage':
      return formatPercent(value / 100, { locale }); // Assume value is 0-100
    default:
      return formatNumber(value, { locale });
  }
}

/**
 * Get the trend direction.
 */
function getTrendDirection(
  change: number | null | undefined
): 'up' | 'down' | 'neutral' {
  if (change == null || change === 0) return 'neutral';
  return change > 0 ? 'up' : 'down';
}

/**
 * Get the trend color based on direction and whether higher is better.
 */
function getTrendColor(
  direction: 'up' | 'down' | 'neutral',
  higherIsBetter: boolean
): 'positive' | 'negative' | 'neutral' {
  if (direction === 'neutral') return 'neutral';

  if (higherIsBetter) {
    return direction === 'up' ? 'positive' : 'negative';
  } else {
    return direction === 'up' ? 'negative' : 'positive';
  }
}

const TREND_ICONS = {
  up: TrendingUp,
  down: TrendingDown,
  neutral: Minus,
};

const TREND_COLORS = {
  positive: 'text-[var(--trend-positive)]',
  negative: 'text-[var(--trend-negative)]',
  neutral: 'text-[var(--trend-neutral)]',
};

/**
 * KpiCard component for displaying key performance indicators.
 *
 * @example
 * ```tsx
 * // Basic KPI
 * <KpiCard label="Revenue" value={125000} valueFormat="currency" />
 *
 * // With change indicator
 * <KpiCard
 *   label="Active Users"
 *   value={1234}
 *   previousValue={1100}
 * />
 *
 * // With sparkline
 * <KpiCard
 *   label="Page Views"
 *   value={45678}
 *   sparklineData={[10, 15, 12, 18, 22, 25, 28]}
 * />
 *
 * // Lower is better (e.g., error rate)
 * <KpiCard
 *   label="Error Rate"
 *   value={2.5}
 *   valueFormat="percentage"
 *   previousValue={3.2}
 *   higherIsBetter={false}
 * />
 * ```
 */
const KpiCard = forwardRef<HTMLElement, KpiCardProps>(
  (
    {
      label,
      value,
      previousValue,
      change: explicitChange,
      valueFormat = 'number',
      locale = 'en-NZ',
      higherIsBetter = true,
      icon,
      sparklineData,
      size = 'md',
      glow = false,
      loading = false,
      className,
      ...props
    },
    ref
  ) => {
    // Calculate change if not explicitly provided
    const change = useMemo(() => {
      if (explicitChange != null) return explicitChange;
      if (previousValue != null && typeof value === 'number') {
        return calculateChange(value, previousValue);
      }
      return null;
    }, [explicitChange, previousValue, value]);

    // Format the display value
    const formattedValue = useMemo(
      () => formatValue(value, valueFormat, locale),
      [value, valueFormat, locale]
    );

    // Get trend info
    const trendDirection = getTrendDirection(change);
    const trendColor = getTrendColor(trendDirection, higherIsBetter);
    const TrendIcon = TREND_ICONS[trendDirection];

    // Size-specific classes
    const sizeClasses = {
      sm: {
        label: 'text-xs',
        value: 'text-lg font-semibold',
        icon: 'h-4 w-4',
        trend: 'text-xs',
        sparkline: { width: 48, height: 16 },
      },
      md: {
        label: 'text-sm',
        value: 'text-2xl font-bold',
        icon: 'h-5 w-5',
        trend: 'text-sm',
        sparkline: { width: 64, height: 24 },
      },
      lg: {
        label: 'text-base',
        value: 'text-3xl font-bold',
        icon: 'h-6 w-6',
        trend: 'text-base',
        sparkline: { width: 80, height: 32 },
      },
    }[size];

    // Loading state
    if (loading) {
      return (
        <article
          ref={ref}
          className={cn(kpiCardVariants({ size, glow }), className)}
          {...props}
        >
          <div className="flex items-center justify-between">
            <Skeleton className="h-4 w-24" />
            {icon && <Skeleton className="h-5 w-5 rounded" />}
          </div>
          <Skeleton className="h-8 w-32" />
          <div className="flex items-center gap-2">
            <Skeleton className="h-4 w-16" />
            {sparklineData && <Skeleton className="h-6 w-16" />}
          </div>
        </article>
      );
    }

    return (
      <article
        ref={ref}
        data-slot="kpi-card"
        className={cn(kpiCardVariants({ size, glow }), className)}
        {...props}
      >
        {/* Header: Label and Icon */}
        <div className="flex items-center justify-between">
          <span className={cn('text-muted-foreground font-medium', sizeClasses.label)}>
            {label}
          </span>
          {icon && (
            <span className={cn('text-muted-foreground', sizeClasses.icon)}>
              {icon}
            </span>
          )}
        </div>

        {/* Main Value */}
        <div className={cn('text-foreground tabular-nums', sizeClasses.value)}>
          {formattedValue}
        </div>

        {/* Footer: Trend and Sparkline */}
        <div className="flex items-center justify-between">
          {/* Trend indicator */}
          {change != null && (
            <div
              className={cn(
                'flex items-center gap-1 font-medium',
                sizeClasses.trend,
                TREND_COLORS[trendColor]
              )}
            >
              <TrendIcon className="h-4 w-4" />
              <span>
                {change > 0 ? '+' : ''}
                {change.toFixed(1)}%
              </span>
            </div>
          )}

          {/* Sparkline */}
          {sparklineData && sparklineData.length > 1 && (
            <Sparkline
              data={sparklineData}
              width={sizeClasses.sparkline.width}
              height={sizeClasses.sparkline.height}
              variant={change != null ? (trendColor === 'neutral' ? 'neutral' : trendColor === 'positive' ? 'positive' : 'negative') : 'auto'}
            />
          )}
        </div>
      </article>
    );
  }
);

KpiCard.displayName = 'KpiCard';

export { KpiCard, kpiCardVariants };
