'use client';

import {
  forwardRef,
  type ComponentPropsWithoutRef,
  type CSSProperties,
  type ElementRef,
  type HTMLAttributes,
} from 'react';
import * as DialogPrimitive from '@radix-ui/react-dialog';
import { cva, type VariantProps } from 'class-variance-authority';
import { X } from 'lucide-react';

import { cn } from '../../utils';

export type DrawerState = 'success' | 'warning' | 'danger' | 'neutral' | 'info';

/** RGB values for glow effect by state */
const GLOW_RGB_MAP: Record<DrawerState, string> = {
  success: '34, 197, 94',
  warning: '234, 179, 8',
  danger: '239, 68, 68',
  info: '59, 130, 246',
  neutral: '156, 163, 175',
};

const drawerContentVariants = cva(
  'fixed inset-y-0 z-50 flex h-full flex-col border bg-background shadow-lg transition-transform duration-300 ease-in-out data-[state=open]:animate-in data-[state=closed]:animate-out',
  {
    variants: {
      side: {
        right:
          'right-0 rounded-tl-[24px] data-[state=closed]:slide-out-to-right data-[state=open]:slide-in-from-right',
        left: 'left-0 rounded-tr-[24px] data-[state=closed]:slide-out-to-left data-[state=open]:slide-in-from-left',
      },
    },
    defaultVariants: {
      side: 'right',
    },
  }
);

export interface DrawerContentProps
  extends ComponentPropsWithoutRef<typeof DialogPrimitive.Content>,
    VariantProps<typeof drawerContentVariants> {
  /** Width of the drawer */
  width?: string | number;
  /** State for glow effect */
  state?: DrawerState;
  /** Show close button */
  showClose?: boolean;
}

/**
 * Drawer component for side panel overlays.
 *
 * @example
 * ```tsx
 * <Drawer>
 *   <DrawerTrigger asChild>
 *     <Button>Open Drawer</Button>
 *   </DrawerTrigger>
 *   <DrawerContent width={400}>
 *     <DrawerHeader>
 *       <DrawerTitle>Edit Profile</DrawerTitle>
 *       <DrawerDescription>Make changes to your profile.</DrawerDescription>
 *     </DrawerHeader>
 *     <DrawerBody>
 *       <DrawerField label="Name" value="John Doe" />
 *       <DrawerField label="Email" value="john@example.com" />
 *     </DrawerBody>
 *     <DrawerFooter>
 *       <Button>Save changes</Button>
 *     </DrawerFooter>
 *   </DrawerContent>
 * </Drawer>
 *
 * // With status glow
 * <DrawerContent state="success">...</DrawerContent>
 * ```
 */
const Drawer = DialogPrimitive.Root;

const DrawerTrigger = DialogPrimitive.Trigger;

const DrawerClose = DialogPrimitive.Close;

const DrawerPortal = DialogPrimitive.Portal;

const DrawerOverlay = forwardRef<
  ElementRef<typeof DialogPrimitive.Overlay>,
  ComponentPropsWithoutRef<typeof DialogPrimitive.Overlay>
>(({ className, ...props }, ref) => (
  <DialogPrimitive.Overlay
    ref={ref}
    data-slot="drawer-overlay"
    className={cn(
      'fixed inset-0 z-50 bg-black/70 backdrop-blur-sm data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0',
      className
    )}
    {...props}
  />
));
DrawerOverlay.displayName = DialogPrimitive.Overlay.displayName;

const DrawerContent = forwardRef<
  ElementRef<typeof DialogPrimitive.Content>,
  DrawerContentProps
>(({ className, children, width = 400, side, state = 'neutral', showClose = true, style, ...props }, ref) => {
  const glowRgb = GLOW_RGB_MAP[state];
  const glowStyle: CSSProperties = {
    width: typeof width === 'number' ? `${width}px` : width,
    '--drawer-glow-rgb': glowRgb,
    ...(state !== 'neutral' && {
      boxShadow: `0 0 30px -5px rgba(${glowRgb}, 0.3)`,
    }),
    ...style,
  } as CSSProperties;

  return (
    <DrawerPortal>
      <DrawerOverlay />
      <DialogPrimitive.Content
        ref={ref}
        data-slot="drawer-content"
        data-state-type={state}
        className={cn(drawerContentVariants({ side }), className)}
        style={glowStyle}
        {...props}
      >
        {children}
        {showClose && (
          <DialogPrimitive.Close
            data-slot="drawer-close"
            className="absolute right-4 top-4 rounded-sm opacity-70 ring-offset-background transition-opacity hover:opacity-100 focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 disabled:pointer-events-none data-[state=open]:bg-secondary"
          >
            <X className="h-4 w-4" />
            <span className="sr-only">Close</span>
          </DialogPrimitive.Close>
        )}
      </DialogPrimitive.Content>
    </DrawerPortal>
  );
});
DrawerContent.displayName = DialogPrimitive.Content.displayName;

export interface DrawerHeaderProps extends HTMLAttributes<HTMLDivElement> {
  /** Show glow effect in header (uses parent drawer's state) */
  showGlow?: boolean;
}

const DrawerHeader = ({
  className,
  showGlow = false,
  children,
  ...props
}: DrawerHeaderProps) => (
  <div
    data-slot="drawer-header"
    className={cn('relative flex flex-col space-y-1.5 border-b px-6 py-4', className)}
    {...props}
  >
    {showGlow && (
      <div
        className="pointer-events-none absolute inset-0 opacity-50"
        style={{
          background: `radial-gradient(circle at 0% 0%, rgba(var(--drawer-glow-rgb), 0.35) 0%, transparent 70%)`,
        }}
      />
    )}
    <div className="relative">{children}</div>
  </div>
);
DrawerHeader.displayName = 'DrawerHeader';

const DrawerBody = ({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) => (
  <div
    data-slot="drawer-body"
    className={cn(
      'flex-1 overflow-y-auto px-6 py-4',
      '[&::-webkit-scrollbar]:w-2 [&::-webkit-scrollbar-thumb]:rounded-full [&::-webkit-scrollbar-thumb]:bg-foreground/15',
      className
    )}
    {...props}
  />
);
DrawerBody.displayName = 'DrawerBody';

export interface DrawerFooterProps extends HTMLAttributes<HTMLDivElement> {
  /** Make footer sticky at bottom during scroll */
  sticky?: boolean;
}

const DrawerFooter = ({
  className,
  sticky = false,
  ...props
}: DrawerFooterProps) => (
  <div
    data-slot="drawer-footer"
    className={cn(
      'flex flex-col-reverse gap-2 border-t px-6 py-4 sm:flex-row sm:justify-end',
      sticky && 'sticky bottom-0 z-[1] bg-card',
      className
    )}
    {...props}
  />
);
DrawerFooter.displayName = 'DrawerFooter';

const DrawerTitle = forwardRef<
  ElementRef<typeof DialogPrimitive.Title>,
  ComponentPropsWithoutRef<typeof DialogPrimitive.Title>
>(({ className, ...props }, ref) => (
  <DialogPrimitive.Title
    ref={ref}
    data-slot="drawer-title"
    className={cn('text-[1.75rem] font-semibold leading-tight tracking-tight', className)}
    {...props}
  />
));
DrawerTitle.displayName = DialogPrimitive.Title.displayName;

const DrawerDescription = forwardRef<
  ElementRef<typeof DialogPrimitive.Description>,
  ComponentPropsWithoutRef<typeof DialogPrimitive.Description>
>(({ className, ...props }, ref) => (
  <DialogPrimitive.Description
    ref={ref}
    data-slot="drawer-description"
    className={cn('text-sm text-muted-foreground', className)}
    {...props}
  />
));
DrawerDescription.displayName = DialogPrimitive.Description.displayName;

export interface DrawerStatusProps extends HTMLAttributes<HTMLDivElement> {
  /** Status type */
  status: DrawerState;
}

const statusColors: Record<DrawerState, string> = {
  success: 'bg-green-500',
  warning: 'bg-yellow-500',
  danger: 'bg-red-500',
  info: 'bg-blue-500',
  neutral: 'bg-gray-500',
};

const DrawerStatus = ({
  className,
  status,
  children,
  ...props
}: DrawerStatusProps) => (
  <div
    data-slot="drawer-status"
    className={cn('flex items-center gap-2 text-sm', className)}
    {...props}
  >
    <span className={cn('h-2 w-2 rounded-full', statusColors[status])} />
    {children}
  </div>
);
DrawerStatus.displayName = 'DrawerStatus';

const DrawerSectionTitle = ({
  className,
  ...props
}: HTMLAttributes<HTMLHeadingElement>) => (
  <h4
    data-slot="drawer-section-title"
    className={cn('mb-2 text-sm font-medium text-muted-foreground', className)}
    {...props}
  />
);
DrawerSectionTitle.displayName = 'DrawerSectionTitle';

export interface DrawerFieldProps extends HTMLAttributes<HTMLDivElement> {
  /** Field label */
  label: string;
  /** Field value */
  value?: string | number | null;
}

const DrawerField = ({
  className,
  label,
  value,
  children,
  ...props
}: DrawerFieldProps) => (
  <div
    data-slot="drawer-field"
    className={cn('py-2', className)}
    {...props}
  >
    <dt className="text-sm text-muted-foreground">{label}</dt>
    <dd className="mt-1 text-sm font-medium">
      {children ?? value ?? '-'}
    </dd>
  </div>
);
DrawerField.displayName = 'DrawerField';

export {
  Drawer,
  DrawerPortal,
  DrawerOverlay,
  DrawerTrigger,
  DrawerClose,
  DrawerContent,
  DrawerHeader,
  DrawerBody,
  DrawerFooter,
  DrawerTitle,
  DrawerDescription,
  DrawerStatus,
  DrawerSectionTitle,
  DrawerField,
};
