'use client';

import { forwardRef, type ComponentPropsWithoutRef } from 'react';
import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '../../utils';

export type AgentType = 'persona-forge' | 'ux-designer' | 'system' | string;

// Agent color definitions
const AGENT_COLORS: Record<
  string,
  { bg: string; border: string; text: string; dot: string }
> = {
  'persona-forge': {
    bg: 'bg-violet-500/10',
    border: 'border-violet-500/30',
    text: 'text-violet-600 dark:text-violet-400',
    dot: 'bg-violet-500',
  },
  'ux-designer': {
    bg: 'bg-teal-500/10',
    border: 'border-teal-500/30',
    text: 'text-teal-600 dark:text-teal-400',
    dot: 'bg-teal-500',
  },
  system: {
    bg: 'bg-muted',
    border: 'border-muted-foreground/20',
    text: 'text-muted-foreground',
    dot: 'bg-muted-foreground',
  },
};

// Default colors for unknown agent types
const DEFAULT_COLORS = {
  bg: 'bg-blue-500/10',
  border: 'border-blue-500/30',
  text: 'text-blue-600 dark:text-blue-400',
  dot: 'bg-blue-500',
};

const agentBadgeVariants = cva(
  'inline-flex items-center gap-1.5 rounded-full border font-mono',
  {
    variants: {
      size: {
        sm: 'px-2 py-0.5 text-[10px]',
        md: 'px-2.5 py-1 text-xs',
      },
    },
    defaultVariants: {
      size: 'sm',
    },
  }
);

export interface AgentBadgeProps
  extends Omit<ComponentPropsWithoutRef<'span'>, 'children'>,
    VariantProps<typeof agentBadgeVariants> {
  /** Agent name to display */
  agent: AgentType;
  /** Whether the agent is currently active/running */
  isActive?: boolean;
  /** Custom display label (defaults to agent name) */
  label?: string;
}

/**
 * AgentBadge - Displays which AI agent is performing a task
 *
 * Used in processing screens to show which agent (persona-forge, ux-designer)
 * is currently working on a task.
 *
 * @example
 * ```tsx
 * <AgentBadge agent="persona-forge" />
 * <AgentBadge agent="ux-designer" isActive />
 * <AgentBadge agent="system" size="md" />
 * ```
 */
const AgentBadge = forwardRef<HTMLSpanElement, AgentBadgeProps>(
  ({ agent, isActive = false, size, label, className, ...props }, ref) => {
    const colors = AGENT_COLORS[agent] || DEFAULT_COLORS;
    const displayName = label || agent;

    return (
      <span
        ref={ref}
        className={cn(
          agentBadgeVariants({ size }),
          colors.bg,
          colors.border,
          colors.text,
          className
        )}
        {...props}
      >
        <span
          className={cn(
            'rounded-full',
            colors.dot,
            size === 'sm' && 'h-1.5 w-1.5',
            size === 'md' && 'h-2 w-2',
            !size && 'h-1.5 w-1.5', // default
            isActive && 'animate-pulse'
          )}
        />
        <span>{displayName}</span>
      </span>
    );
  }
);

AgentBadge.displayName = 'AgentBadge';

/**
 * Get the color class for an agent (for use in other components)
 */
function getAgentColorClass(agent: AgentType): string {
  return (AGENT_COLORS[agent] || DEFAULT_COLORS).text;
}

/**
 * Get the background color for an agent
 */
function getAgentBgClass(agent: AgentType): string {
  return (AGENT_COLORS[agent] || DEFAULT_COLORS).bg;
}

/**
 * Register a custom agent type with colors
 */
function registerAgentType(
  name: string,
  colors: { bg: string; border: string; text: string; dot: string }
): void {
  AGENT_COLORS[name] = colors;
}

export {
  AgentBadge,
  agentBadgeVariants,
  getAgentColorClass,
  getAgentBgClass,
  registerAgentType,
};
