'use client';

import { forwardRef, type ComponentPropsWithoutRef } from 'react';

import { cn } from '../../utils';
import { Progress } from './progress';

export interface OverallProgressBarProps
  extends Omit<ComponentPropsWithoutRef<'div'>, 'children'> {
  /** Number of completed steps */
  completedSteps: number;
  /** Total number of steps (default 18) */
  totalSteps?: number;
  /** Current step label */
  currentStepLabel?: string;
  /** Whether generation is active */
  isActive?: boolean;
  /** Whether to show step dots below the bar */
  showStepDots?: boolean;
}

/**
 * OverallProgressBar - Shows overall progress with step counter
 *
 * Displays a header with step counter, gradient progress bar,
 * and optional step indicator dots.
 *
 * @example
 * ```tsx
 * // Basic usage
 * <OverallProgressBar
 *   completedSteps={6}
 *   totalSteps={18}
 *   isActive
 * />
 *
 * // With current step label
 * <OverallProgressBar
 *   completedSteps={12}
 *   totalSteps={18}
 *   currentStepLabel="KPIs"
 *   isActive
 * />
 *
 * // Complete state
 * <OverallProgressBar
 *   completedSteps={18}
 *   totalSteps={18}
 * />
 * ```
 */
const OverallProgressBar = forwardRef<HTMLDivElement, OverallProgressBarProps>(
  (
    {
      completedSteps,
      totalSteps = 18,
      currentStepLabel,
      isActive = false,
      showStepDots = true,
      className,
      ...props
    },
    ref
  ) => {
    const progressPercent = Math.round((completedSteps / totalSteps) * 100);
    const isComplete = completedSteps >= totalSteps;
    const currentStepNumber = Math.min(completedSteps + 1, totalSteps);

    return (
      <div ref={ref} className={cn('space-y-2', className)} {...props}>
        {/* Header */}
        <div className="flex items-center justify-between text-sm">
          <div className="flex items-center gap-2">
            {isActive && !isComplete && (
              <span className="relative flex h-2 w-2">
                <span className="absolute inline-flex h-full w-full animate-ping rounded-full bg-orange-400 opacity-75" />
                <span className="relative inline-flex h-2 w-2 rounded-full bg-orange-500" />
              </span>
            )}
            <span className="font-medium">
              {isComplete
                ? 'Complete'
                : `Step ${currentStepNumber} of ${totalSteps}`}
            </span>
            {currentStepLabel && !isComplete && (
              <>
                <span className="text-muted-foreground">·</span>
                <span className="text-muted-foreground">{currentStepLabel}</span>
              </>
            )}
          </div>
          <span className="font-medium tabular-nums">{progressPercent}%</span>
        </div>

        {/* Progress bar */}
        <Progress
          value={progressPercent}
          className={cn(
            'h-2',
            isActive &&
              !isComplete &&
              '[&>[data-slot=indicator]]:bg-gradient-to-r [&>[data-slot=indicator]]:from-orange-500 [&>[data-slot=indicator]]:to-teal-500'
          )}
        />

        {/* Step dots */}
        {showStepDots && (
          <div className="flex gap-0.5">
            {Array.from({ length: totalSteps }).map((_, i) => (
              <div
                key={i}
                className={cn(
                  'h-1 flex-1 rounded-full transition-colors',
                  i < completedSteps
                    ? 'bg-teal-500'
                    : i === completedSteps && isActive
                      ? 'bg-orange-500 animate-pulse'
                      : 'bg-muted'
                )}
              />
            ))}
          </div>
        )}
      </div>
    );
  }
);

OverallProgressBar.displayName = 'OverallProgressBar';

/**
 * CompactProgressIndicator - Minimal progress for header/nav
 *
 * Shows step count and a small progress bar, suitable for
 * navigation headers or compact layouts.
 *
 * @example
 * ```tsx
 * <CompactProgressIndicator
 *   completedSteps={6}
 *   totalSteps={18}
 *   isActive
 * />
 * ```
 */
export interface CompactProgressIndicatorProps
  extends Omit<ComponentPropsWithoutRef<'div'>, 'children'> {
  /** Number of completed steps */
  completedSteps: number;
  /** Total number of steps (default 18) */
  totalSteps?: number;
  /** Whether generation is active */
  isActive?: boolean;
}

const CompactProgressIndicator = forwardRef<
  HTMLDivElement,
  CompactProgressIndicatorProps
>(({ completedSteps, totalSteps = 18, isActive = false, className, ...props }, ref) => {
  const progressPercent = Math.round((completedSteps / totalSteps) * 100);

  return (
    <div
      ref={ref}
      className={cn('flex items-center gap-2', className)}
      {...props}
    >
      {isActive && (
        <span className="relative flex h-2 w-2">
          <span className="absolute inline-flex h-full w-full animate-ping rounded-full bg-orange-400 opacity-75" />
          <span className="relative inline-flex h-2 w-2 rounded-full bg-orange-500" />
        </span>
      )}
      <div className="flex items-center gap-1 text-xs text-muted-foreground">
        <span className="font-medium tabular-nums">
          {completedSteps}/{totalSteps}
        </span>
        <Progress value={progressPercent} className="h-1 w-16" />
      </div>
    </div>
  );
});

CompactProgressIndicator.displayName = 'CompactProgressIndicator';

export { OverallProgressBar, CompactProgressIndicator };
