'use client';

import { AlertCircle } from 'lucide-react';
import type { ReactNode } from 'react';

import { cn } from '../../utils';
import { Label } from './label';

export interface FormFieldProps {
  /** Field label */
  label?: string;
  /** HTML for attribute - links label to input */
  htmlFor?: string;
  /** Error message to display */
  error?: string;
  /** Helper/description text (hidden when error shown) */
  description?: string;
  /** Whether the field is required (shows asterisk) */
  required?: boolean;
  /** The form input element(s) */
  children: ReactNode;
  /** Additional className */
  className?: string;
}

/**
 * FormField component for wrapping form inputs with label, error, and description.
 *
 * @example
 * ```tsx
 * // Basic field
 * <FormField label="Email" htmlFor="email">
 *   <Input id="email" type="email" />
 * </FormField>
 *
 * // Required field with description
 * <FormField
 *   label="Password"
 *   htmlFor="password"
 *   required
 *   description="Must be at least 8 characters"
 * >
 *   <Input id="password" type="password" />
 * </FormField>
 *
 * // With error
 * <FormField
 *   label="Username"
 *   htmlFor="username"
 *   error="Username is already taken"
 * >
 *   <Input id="username" />
 * </FormField>
 * ```
 */
export function FormField({
  label,
  htmlFor,
  error,
  description,
  required,
  children,
  className,
}: FormFieldProps) {
  return (
    <div data-slot="form-field" className={cn('space-y-2', className)}>
      {label && (
        <Label
          htmlFor={htmlFor}
          className={cn(error && 'text-destructive')}
        >
          {label}
          {required && <span className="ml-1 text-destructive">*</span>}
        </Label>
      )}
      {children}
      {description && !error && (
        <p className="text-sm text-muted-foreground">{description}</p>
      )}
      {error && (
        <p className="flex items-center gap-1.5 text-sm text-destructive">
          <AlertCircle className="h-3.5 w-3.5 shrink-0" />
          {error}
        </p>
      )}
    </div>
  );
}
