'use client';

import { forwardRef, type ComponentPropsWithoutRef } from 'react';

import { cn } from '../../utils';

export interface SteppedProgressBarProps
  extends Omit<ComponentPropsWithoutRef<'div'>, 'children'> {
  /** Progress value 0-100 */
  progress: number;
  /** Number of segments (default 10) */
  segments?: number;
  /** Height in pixels (default 4) */
  height?: number;
  /** Color variant */
  variant?: 'default' | 'success' | 'warning' | 'danger';
}

/**
 * SteppedProgressBar - Segmented progress bar (Netflix/YouTube style)
 *
 * Shows progress as filled segments with primary color.
 *
 * @example
 * ```tsx
 * // Basic usage
 * <SteppedProgressBar progress={75} />
 *
 * // Custom segments and height
 * <SteppedProgressBar progress={60} segments={5} height={8} />
 *
 * // Color variants
 * <SteppedProgressBar progress={90} variant="danger" />
 * ```
 */
const SteppedProgressBar = forwardRef<HTMLDivElement, SteppedProgressBarProps>(
  (
    {
      progress,
      segments = 10,
      height = 4,
      variant = 'default',
      className,
      ...props
    },
    ref
  ) => {
    const filledSegments = Math.round((progress / 100) * segments);

    const getVariantClasses = (filled: boolean) => {
      if (!filled) return 'bg-primary/15';

      switch (variant) {
        case 'success':
          return 'bg-[var(--status-success)]';
        case 'warning':
          return 'bg-[var(--status-warning)]';
        case 'danger':
          return 'bg-[var(--status-danger)]';
        default:
          return 'bg-primary';
      }
    };

    return (
      <div
        ref={ref}
        role="progressbar"
        aria-valuenow={progress}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-label={`${Math.round(progress)}% complete`}
        className={cn('flex gap-0.5', className)}
        {...props}
      >
        {Array.from({ length: segments }).map((_, index) => {
          const filled = index < filledSegments;
          return (
            <div
              key={index}
              className={cn(
                'flex-1 rounded-sm transition-colors duration-150',
                getVariantClasses(filled)
              )}
              style={{ height: `${height}px` }}
            />
          );
        })}
      </div>
    );
  }
);

SteppedProgressBar.displayName = 'SteppedProgressBar';

export { SteppedProgressBar };
