'use client';

import * as ProgressPrimitive from '@radix-ui/react-progress';
import {
  forwardRef,
  type ComponentPropsWithoutRef,
  type ElementRef,
} from 'react';
import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '../../utils';

const progressVariants = cva(
  'relative w-full overflow-hidden rounded-full',
  {
    variants: {
      size: {
        sm: 'h-1',
        md: 'h-2',
        lg: 'h-3',
      },
      variant: {
        default: 'bg-primary/20',
        success: 'bg-green-500/20',
        warning: 'bg-yellow-500/20',
        danger: 'bg-red-500/20',
        info: 'bg-blue-500/20',
      },
    },
    defaultVariants: {
      size: 'md',
      variant: 'default',
    },
  }
);

const indicatorVariants = cva(
  'h-full w-full flex-1 transition-all',
  {
    variants: {
      variant: {
        default: 'bg-primary',
        success: 'bg-green-500',
        warning: 'bg-yellow-500',
        danger: 'bg-red-500',
        info: 'bg-blue-500',
      },
      indeterminate: {
        true: 'animate-progress-indeterminate',
        false: '',
      },
    },
    defaultVariants: {
      variant: 'default',
      indeterminate: false,
    },
  }
);

interface ProgressProps
  extends ComponentPropsWithoutRef<typeof ProgressPrimitive.Root>,
    VariantProps<typeof progressVariants> {
  /** Progress value from 0 to 100 */
  value?: number;
  /** Color variant */
  variant?: 'default' | 'success' | 'warning' | 'danger' | 'info';
  /** Show indeterminate animation (ignores value) */
  indeterminate?: boolean;
  /** Show percentage label */
  showLabel?: boolean;
  /** Custom label (overrides percentage) */
  label?: string;
  /** Optional indicator class for custom colors */
  indicatorClassName?: string;
}

const Progress = forwardRef<
  ElementRef<typeof ProgressPrimitive.Root>,
  ProgressProps
>(({
  className,
  value,
  size,
  variant = 'default',
  indeterminate = false,
  showLabel = false,
  label,
  indicatorClassName,
  ...props
}, ref) => {
  const displayValue = indeterminate ? undefined : value;
  const labelText = label ?? (value !== undefined ? `${Math.round(value)}%` : '');

  return (
    <div className={cn('flex items-center gap-2', showLabel && 'w-full')}>
      <ProgressPrimitive.Root
        ref={ref}
        data-slot="progress"
        className={cn(progressVariants({ size, variant }), className)}
        value={displayValue}
        {...props}
      >
        <ProgressPrimitive.Indicator
          className={cn(
            indicatorVariants({ variant, indeterminate }),
            indicatorClassName
          )}
          style={!indeterminate ? { transform: `translateX(-${100 - (value || 0)}%)` } : undefined}
        />
      </ProgressPrimitive.Root>
      {showLabel && (
        <span className="text-sm tabular-nums text-muted-foreground min-w-[3ch] text-right">
          {labelText}
        </span>
      )}
    </div>
  );
});
Progress.displayName = ProgressPrimitive.Root.displayName;

export { Progress, progressVariants, indicatorVariants };
export type { ProgressProps };
