'use client';

import { cva, type VariantProps } from 'class-variance-authority';
import { forwardRef, useMemo, type ComponentPropsWithoutRef } from 'react';

import { cn } from '../../utils';

export type CapacityStatus = 'low' | 'medium' | 'high' | 'critical';

export interface CapacityThresholds {
  /** Threshold for low (success) - percentage below this is green */
  low: number;
  /** Threshold for medium (warning) - percentage below this is yellow */
  medium: number;
  /** Threshold for high - percentage below this is orange */
  high: number;
}

export interface CapacityBarProps
  extends Omit<ComponentPropsWithoutRef<'div'>, 'children'>,
    VariantProps<typeof capacityBarVariants> {
  /** Current value */
  value: number;
  /** Maximum value */
  max: number;
  /** Label for the capacity bar */
  label?: string;
  /** Whether to show the numeric value */
  showValue?: boolean;
  /** Value format template: '{value}', '{max}', '{percent}' */
  valueFormat?: string;
  /** Number of visual segments */
  segments?: number;
  /** Size variant: 'xs' (1px), 'sm' (2px), 'md' (4px), 'lg' (8px) */
  size?: 'xs' | 'sm' | 'md' | 'lg';
  /** Custom color thresholds (percentages) */
  thresholds?: CapacityThresholds;
  /** Visual emphasis with glow effect (default: true) */
  glow?: boolean;
  /** Whether to animate on mount and value changes */
  animated?: boolean;
  /** Accessible description */
  'aria-label'?: string;
}

const capacityBarVariants = cva('flex flex-col gap-1.5', {
  variants: {
    size: {
      xs: '',
      sm: '',
      md: '',
      lg: '',
    },
  },
  defaultVariants: {
    size: 'md',
  },
});

/** Size to height mapping */
const sizeHeightMap = {
  xs: 'h-px',     // 1px
  sm: 'h-0.5',    // 2px
  md: 'h-1',      // 4px
  lg: 'h-2',      // 8px
} as const;

const DEFAULT_THRESHOLDS: CapacityThresholds = {
  low: 40,
  medium: 60,
  high: 80,
};

/**
 * Get the status category based on percentage and thresholds.
 */
function getCapacityStatus(
  percent: number,
  thresholds: CapacityThresholds
): CapacityStatus {
  if (percent <= thresholds.low) return 'low';
  if (percent <= thresholds.medium) return 'medium';
  if (percent <= thresholds.high) return 'high';
  return 'critical';
}

/**
 * Get the color and glow classes for a segment based on its index and filled count.
 */
function getSegmentStyles(
  segmentIndex: number,
  filledSegments: number,
  totalSegments: number,
  glow: boolean
): { bg: string; glow: string } {
  // Segment is not filled
  if (segmentIndex >= filledSegments) {
    return { bg: 'bg-muted', glow: '' };
  }

  // Color based on position within the filled segments
  const segmentPercent = ((segmentIndex + 1) / totalSegments) * 100;

  if (segmentPercent <= 40) {
    return {
      bg: 'bg-[var(--capacity-low)]',
      glow: glow ? 'shadow-[0_0_10px_var(--capacity-low)]' : '',
    };
  }
  if (segmentPercent <= 60) {
    return {
      bg: 'bg-[var(--capacity-medium)]',
      glow: glow ? 'shadow-[0_0_10px_var(--capacity-medium)]' : '',
    };
  }
  if (segmentPercent <= 80) {
    return {
      bg: 'bg-[var(--capacity-high)]',
      glow: glow ? 'shadow-[0_0_10px_var(--capacity-high)]' : '',
    };
  }
  return {
    bg: 'bg-[var(--capacity-critical)]',
    glow: glow ? 'shadow-[0_0_12px_var(--capacity-critical)]' : '',
  };
}

/**
 * Format the value display based on the format template.
 */
function formatValue(
  value: number,
  max: number,
  percent: number,
  format: string
): string {
  return format
    .replace('{value}', String(value))
    .replace('{max}', String(max))
    .replace('{percent}', String(Math.round(percent)));
}

/**
 * CapacityBar component for displaying capacity/progress with color-coded segments.
 *
 * @example
 * ```tsx
 * // Basic usage
 * <CapacityBar value={75} max={100} />
 *
 * // With label and value display
 * <CapacityBar
 *   value={45}
 *   max={100}
 *   label="Storage Used"
 *   showValue
 * />
 *
 * // Custom segments and thresholds
 * <CapacityBar
 *   value={85}
 *   max={100}
 *   segments={10}
 *   thresholds={{ low: 30, medium: 50, high: 70 }}
 * />
 * ```
 */
const CapacityBar = forwardRef<HTMLDivElement, CapacityBarProps>(
  (
    {
      value,
      max,
      label,
      showValue = true,
      valueFormat = '{percent}%',
      segments = 5,
      size = 'md',
      thresholds = DEFAULT_THRESHOLDS,
      glow = true,
      animated = true,
      'aria-label': ariaLabel,
      className,
      ...props
    },
    ref
  ) => {
    // Calculate percentage
    const percent = useMemo(() => {
      if (max === 0) return 0;
      return Math.min(100, Math.max(0, (value / max) * 100));
    }, [value, max]);

    // Calculate filled segments
    const filledSegments = useMemo(() => {
      return Math.round((percent / 100) * segments);
    }, [percent, segments]);

    // Get status for glow color
    const status = useMemo(
      () => getCapacityStatus(percent, thresholds),
      [percent, thresholds]
    );

    // Format display value
    const displayValue = useMemo(
      () => formatValue(value, max, percent, valueFormat),
      [value, max, percent, valueFormat]
    );

    // Check for reduced motion preference
    const prefersReducedMotion =
      typeof window !== 'undefined' &&
      window.matchMedia?.('(prefers-reduced-motion: reduce)').matches;

    const shouldAnimate = animated && !prefersReducedMotion;

    // Size-specific classes using the height map
    const segmentHeight = sizeHeightMap[size as keyof typeof sizeHeightMap] || sizeHeightMap.md;
    const segmentGap = size === 'xs' || size === 'sm' ? 'gap-px' : 'gap-0.5';

    return (
      <div
        ref={ref}
        data-slot="capacity-bar"
        data-status={status}
        className={cn(capacityBarVariants({ size }), className)}
        {...props}
      >
        {/* Header: Label and Value */}
        {(label || showValue) && (
          <div className="flex items-center justify-between text-sm">
            {label && (
              <span className="text-muted-foreground font-medium">{label}</span>
            )}
            {showValue && (
              <span className="text-foreground tabular-nums">{displayValue}</span>
            )}
          </div>
        )}

        {/* Segments container */}
        <div
          role="meter"
          aria-valuenow={value}
          aria-valuemin={0}
          aria-valuemax={max}
          aria-label={ariaLabel || label || `${Math.round(percent)}% capacity`}
          className={cn('flex w-full', segmentGap)}
        >
          {Array.from({ length: segments }, (_, index) => {
            const isFilled = index < filledSegments;
            const styles = getSegmentStyles(index, filledSegments, segments, glow);

            return (
              <div
                key={index}
                data-slot="capacity-segment"
                data-filled={isFilled || undefined}
                className={cn(
                  'flex-1 rounded-sm transition-all',
                  segmentHeight,
                  styles.bg,
                  styles.glow,
                  // Animation
                  shouldAnimate && 'origin-left',
                  shouldAnimate &&
                    isFilled &&
                    'animate-[tarva-segment-fill_var(--duration-normal)_var(--ease-out)_forwards]',
                  shouldAnimate && {
                    animationDelay: `${index * 50}ms`,
                  }
                )}
                style={
                  shouldAnimate && isFilled
                    ? { animationDelay: `${index * 50}ms` }
                    : undefined
                }
              />
            );
          })}
        </div>
      </div>
    );
  }
);

CapacityBar.displayName = 'CapacityBar';

export { CapacityBar, capacityBarVariants };
