'use client';

import { cva, type VariantProps } from 'class-variance-authority';
import { AlertCircle, RefreshCw } from 'lucide-react';
import type { ReactNode } from 'react';

import { cn } from '../../utils';
import { Button } from './button';

const errorStateVariants = cva(
  'flex flex-col items-center justify-center px-4 text-center',
  {
    variants: {
      size: {
        sm: 'py-6',
        default: 'py-12',
        lg: 'py-16',
      },
      fullPage: {
        true: 'min-h-[400px]',
        false: '',
      },
    },
    defaultVariants: {
      size: 'default',
      fullPage: false,
    },
  }
);

const iconSizeClasses = {
  sm: 'h-8 w-8',
  default: 'h-12 w-12',
  lg: 'h-16 w-16',
};

const iconInnerSizeClasses = {
  sm: 'h-4 w-4',
  default: 'h-6 w-6',
  lg: 'h-8 w-8',
};

export interface ErrorStateProps extends VariantProps<typeof errorStateVariants> {
  /** Error title */
  title?: string;
  /** Error message or description */
  message?: string;
  /** Retry handler - shows retry button when provided */
  onRetry?: () => void;
  /** Custom retry button label */
  retryLabel?: string;
  /** Custom icon */
  icon?: ReactNode;
  /** Additional className */
  className?: string;
}

/**
 * ErrorState component for displaying error conditions.
 *
 * @example
 * ```tsx
 * // Basic error
 * <ErrorState />
 *
 * // With custom message
 * <ErrorState
 *   title="Connection failed"
 *   message="Unable to connect to the server. Check your internet connection."
 * />
 *
 * // With retry button
 * <ErrorState
 *   title="Failed to load data"
 *   message="Something went wrong while fetching the data."
 *   onRetry={() => refetch()}
 * />
 *
 * // Full-page error
 * <ErrorState fullPage title="404 - Page not found" />
 * ```
 */
export function ErrorState({
  title = 'Something went wrong',
  message = 'An unexpected error occurred. Please try again.',
  onRetry,
  retryLabel = 'Try again',
  icon,
  size = 'default',
  fullPage = false,
  className,
}: ErrorStateProps) {
  const sizeKey = size ?? 'default';

  return (
    <div
      data-slot="error-state"
      className={cn(errorStateVariants({ size, fullPage }), className)}
    >
      <div
        className={cn(
          'mb-4 flex items-center justify-center rounded-full bg-destructive/10 text-destructive',
          iconSizeClasses[sizeKey]
        )}
      >
        {icon ?? <AlertCircle className={iconInnerSizeClasses[sizeKey]} />}
      </div>
      <h3 className="text-lg font-semibold text-foreground">{title}</h3>
      {message && (
        <p className="mt-1 max-w-sm text-sm text-muted-foreground">{message}</p>
      )}
      {onRetry && (
        <Button onClick={onRetry} variant="outline" className="mt-4 gap-2">
          <RefreshCw className="h-4 w-4" />
          {retryLabel}
        </Button>
      )}
    </div>
  );
}
