'use client';

import { forwardRef, memo, useEffect, useState, type ComponentPropsWithoutRef } from 'react';

import { cn } from '../../utils';

export type StepClusterStatus =
  | 'pending'
  | 'active'
  | 'completed'
  | 'error'
  | 'skipped';

export interface StepClusterProps
  extends Omit<ComponentPropsWithoutRef<'div'>, 'onClick'> {
  /** Current status of this step */
  status: StepClusterStatus;
  /** Number of sub-tasks completed (0-4) */
  subTaskProgress: number;
  /** Optional label for the step */
  label?: string;
  /** Show step number below cluster */
  showNumber?: boolean;
  /** Step number to display */
  stepNumber?: number;
  /** Called when step is clicked */
  onClick?: () => void;
}

/**
 * Sub-task fill order (clockwise from top-left)
 * A (top-left) -> B (top-right) -> D (bottom-right) -> C (bottom-left)
 */
const BIN_POSITIONS = ['A', 'B', 'D', 'C'] as const;
type BinPosition = (typeof BIN_POSITIONS)[number];

function isBinFilled(position: BinPosition, subTaskProgress: number): boolean {
  const index = BIN_POSITIONS.indexOf(position);
  if (index === -1) return false;
  return subTaskProgress > index;
}

function isCurrentBin(position: BinPosition, subTaskProgress: number): boolean {
  const index = BIN_POSITIONS.indexOf(position);
  if (index === -1) return false;
  // Current bin is the one being filled (subTaskProgress equals its 0-based index)
  return subTaskProgress === index;
}

/**
 * StepCluster - 2x2 bin visualization for step progress
 *
 * Used in step progress grids to show individual step completion with
 * 4 sub-tasks that fill in clockwise order.
 *
 * @example
 * ```tsx
 * // Pending step
 * <StepCluster status="pending" subTaskProgress={0} />
 *
 * // Active step with 2 sub-tasks done
 * <StepCluster status="active" subTaskProgress={2} />
 *
 * // Completed step
 * <StepCluster status="completed" subTaskProgress={4} />
 *
 * // With step number
 * <StepCluster status="active" subTaskProgress={1} showNumber stepNumber={5} />
 * ```
 */
const StepCluster = forwardRef<HTMLDivElement, StepClusterProps>(
  (
    {
      status,
      subTaskProgress,
      label,
      showNumber = false,
      stepNumber,
      onClick,
      className,
      ...props
    },
    ref
  ) => {
    // Track just-completed animation
    const [showCompletePop, setShowCompletePop] = useState(false);
    const [showErrorShake, setShowErrorShake] = useState(false);

    // Trigger completion animation when status changes to completed
    useEffect(() => {
      if (status === 'completed') {
        setShowCompletePop(true);
        const timer = setTimeout(() => setShowCompletePop(false), 300);
        return () => clearTimeout(timer);
      }
      return undefined;
    }, [status]);

    // Trigger error animation when status changes to error
    useEffect(() => {
      if (status === 'error') {
        setShowErrorShake(true);
        const timer = setTimeout(() => setShowErrorShake(false), 300);
        return () => clearTimeout(timer);
      }
      return undefined;
    }, [status]);

    const isActive = status === 'active';
    const isCompleted = status === 'completed';
    const isError = status === 'error';
    const isSkipped = status === 'skipped';
    const isPending = status === 'pending';

    const handleKeyDown = (e: React.KeyboardEvent) => {
      if (onClick && (e.key === 'Enter' || e.key === ' ')) {
        e.preventDefault();
        onClick();
      }
    };

    return (
      <div
        ref={ref}
        className={cn('relative inline-flex flex-col items-center', className)}
        onClick={onClick}
        onKeyDown={handleKeyDown}
        role={onClick ? 'button' : undefined}
        tabIndex={onClick ? 0 : undefined}
        aria-label={`Step ${stepNumber || ''}: ${label || 'Step'} - ${status}`}
        {...props}
      >
        {/* 2x2 bin grid */}
        <div
          className={cn(
            'grid grid-cols-2 gap-[1px] rounded-[3px] p-[1px]',
            // Active state - glow animation
            isActive && 'animate-step-cluster-glow',
            // Completed pop animation
            showCompletePop && 'animate-step-cluster-pop',
            // Error shake animation
            showErrorShake && 'animate-status-shake',
            // Error state styling
            isError && 'ring-1 ring-destructive',
            // Skipped state styling
            isSkipped && 'border border-dashed border-muted opacity-50'
          )}
        >
          {/* Top row: A, B */}
          <Bin
            filled={isBinFilled('A', subTaskProgress)}
            filling={isActive && isCurrentBin('A', subTaskProgress)}
            status={status}
          />
          <Bin
            filled={isBinFilled('B', subTaskProgress)}
            filling={isActive && isCurrentBin('B', subTaskProgress)}
            status={status}
          />
          {/* Bottom row: C, D (visual order C, D but fill order D, C) */}
          <Bin
            filled={isBinFilled('C', subTaskProgress)}
            filling={isActive && isCurrentBin('C', subTaskProgress)}
            status={status}
          />
          <Bin
            filled={isBinFilled('D', subTaskProgress)}
            filling={isActive && isCurrentBin('D', subTaskProgress)}
            status={status}
          />
        </div>

        {/* Step number below */}
        {showNumber && stepNumber !== undefined && (
          <span
            className={cn(
              'mt-1 text-[9px] font-medium tabular-nums',
              isPending && 'text-muted-foreground/50',
              isActive && 'text-primary',
              isCompleted && 'text-muted-foreground',
              isError && 'text-destructive',
              isSkipped && 'text-muted-foreground/50'
            )}
          >
            {stepNumber}
          </span>
        )}
      </div>
    );
  }
);

StepCluster.displayName = 'StepCluster';

// Bin Sub-component
interface BinProps {
  filled: boolean;
  filling: boolean;
  status: StepClusterStatus;
}

const Bin = memo(function Bin({ filled, filling, status }: BinProps) {
  const isError = status === 'error';
  const isSkipped = status === 'skipped';

  return (
    <div
      className={cn(
        'h-1 w-1 rounded-[1px] transition-colors duration-150',
        // Empty state
        !filled && 'bg-[var(--step-bin-empty)]',
        // Filled states
        filled && !filling && 'bg-[var(--step-bin-filled)]',
        // Currently filling - brightest + animation
        filling && 'bg-[var(--step-bin-active)] animate-pulse',
        // Error state - muted
        isError && filled && 'bg-destructive/60',
        isError && !filled && 'bg-destructive/20',
        // Skipped state - empty
        isSkipped && 'bg-[var(--step-bin-empty)]'
      )}
    />
  );
});

export { StepCluster };
