'use client';

import {
  forwardRef,
  useEffect,
  useRef,
  useState,
  type ComponentPropsWithoutRef,
} from 'react';

import { cn } from '../../utils';

export type SparklineVariant = 'positive' | 'negative' | 'neutral' | 'auto';

export interface SparklineProps
  extends Omit<ComponentPropsWithoutRef<'svg'>, 'children'> {
  /** Data points to visualize */
  data: number[];
  /** Width in pixels */
  width?: number;
  /** Height in pixels */
  height?: number;
  /** Stroke width in pixels */
  strokeWidth?: number;
  /** Visual variant based on trend */
  variant?: SparklineVariant;
  /** Whether to show fill gradient under line */
  showFill?: boolean;
  /** Whether to animate on mount */
  animated?: boolean;
  /** Accessible label for screen readers */
  'aria-label'?: string;
}

/**
 * Calculate the trend direction from data.
 */
function calculateTrend(data: number[]): 'positive' | 'negative' | 'neutral' {
  if (data.length < 2) return 'neutral';
  const first = data[0]!;
  const last = data[data.length - 1]!;
  if (last > first) return 'positive';
  if (last < first) return 'negative';
  return 'neutral';
}

/**
 * Generate SVG path points from data.
 */
function generatePoints(
  data: number[],
  width: number,
  height: number,
  padding: number = 2
): string {
  if (data.length === 0) return '';
  if (data.length === 1) {
    // Single point - draw a horizontal line in the middle
    const y = height / 2;
    return `${padding},${y} ${width - padding},${y}`;
  }

  const min = Math.min(...data);
  const max = Math.max(...data);
  const range = max - min || 1; // Avoid division by zero

  const innerWidth = width - padding * 2;
  const innerHeight = height - padding * 2;

  return data
    .map((value, index) => {
      const x = padding + (index / (data.length - 1)) * innerWidth;
      const y = padding + innerHeight - ((value - min) / range) * innerHeight;
      return `${x.toFixed(2)},${y.toFixed(2)}`;
    })
    .join(' ');
}

const VARIANT_COLORS: Record<SparklineVariant | 'positive' | 'negative' | 'neutral', string> = {
  positive: 'var(--trend-positive)',
  negative: 'var(--trend-negative)',
  neutral: 'var(--trend-neutral)',
  auto: 'var(--trend-neutral)', // Fallback, will be overridden
};

/**
 * Sparkline component for displaying mini line charts.
 *
 * @example
 * ```tsx
 * // Auto-detect trend from data
 * <Sparkline data={[10, 15, 12, 18, 22]} />
 *
 * // Force positive color
 * <Sparkline data={[10, 15, 12, 18, 22]} variant="positive" />
 *
 * // With fill gradient
 * <Sparkline data={[10, 15, 12, 18, 22]} showFill />
 * ```
 */
const Sparkline = forwardRef<SVGSVGElement, SparklineProps>(
  (
    {
      data,
      width = 64,
      height = 24,
      strokeWidth = 1.5,
      variant = 'auto',
      showFill = false,
      animated = true,
      'aria-label': ariaLabel,
      className,
      style,
      ...props
    },
    ref
  ) => {
    const pathRef = useRef<SVGPolylineElement>(null);
    const [pathLength, setPathLength] = useState<number>(0);

    // Calculate the resolved variant
    const resolvedVariant =
      variant === 'auto' ? calculateTrend(data) : variant;
    const strokeColor = VARIANT_COLORS[resolvedVariant];

    // Generate path points
    const points = generatePoints(data, width, height);

    // Calculate path length for animation
    useEffect(() => {
      if (animated && pathRef.current) {
        const length = pathRef.current.getTotalLength?.() ?? 0;
        setPathLength(length);
      }
    }, [animated, points]);

    // Check for reduced motion preference
    const prefersReducedMotion =
      typeof window !== 'undefined' &&
      window.matchMedia?.('(prefers-reduced-motion: reduce)').matches;

    const shouldAnimate = animated && !prefersReducedMotion && pathLength > 0;

    // Generate unique IDs for gradient
    const gradientId = `sparkline-gradient-${Math.random().toString(36).slice(2, 9)}`;

    // Accessible label
    const label =
      ariaLabel || `Trend chart showing ${data.length} data points`;

    return (
      <svg
        ref={ref}
        data-slot="sparkline"
        data-variant={resolvedVariant}
        role="img"
        aria-label={label}
        viewBox={`0 0 ${width} ${height}`}
        width={width}
        height={height}
        className={cn('shrink-0', className)}
        style={style}
        {...props}
      >
        <title>{label}</title>

        {/* Gradient definition for fill */}
        {showFill && (
          <defs>
            <linearGradient id={gradientId} x1="0" x2="0" y1="0" y2="1">
              <stop offset="0%" stopColor={strokeColor} stopOpacity="0.3" />
              <stop offset="100%" stopColor={strokeColor} stopOpacity="0" />
            </linearGradient>
          </defs>
        )}

        {/* Fill area */}
        {showFill && data.length > 1 && (
          <polygon
            points={`${2},${height - 2} ${points} ${width - 2},${height - 2}`}
            fill={`url(#${gradientId})`}
            className={cn(
              shouldAnimate && 'animate-fade-in',
              shouldAnimate && 'opacity-0'
            )}
            style={
              shouldAnimate
                ? {
                    animation: `tarva-fade-in var(--duration-slow) var(--ease-out) forwards`,
                    animationDelay: 'var(--duration-normal)',
                  }
                : undefined
            }
          />
        )}

        {/* Line */}
        <polyline
          ref={pathRef}
          points={points}
          fill="none"
          stroke={strokeColor}
          strokeWidth={strokeWidth}
          strokeLinecap="round"
          strokeLinejoin="round"
          style={
            shouldAnimate
              ? {
                  strokeDasharray: pathLength,
                  strokeDashoffset: pathLength,
                  animation: `tarva-sparkline-draw var(--duration-slow) var(--ease-out) forwards`,
                }
              : undefined
          }
        />
      </svg>
    );
  }
);

Sparkline.displayName = 'Sparkline';

export { Sparkline };
