'use client';

import * as React from 'react';

import { cn } from '../../utils';

interface StickyActionBarProps {
  /** Left side content (status, info text) */
  leftContent?: React.ReactNode;
  /** Primary action button (required) */
  primaryAction: React.ReactNode;
  /** Secondary action (optional icon button) */
  secondaryAction?: React.ReactNode;
  /** Whether the bar is visible */
  visible?: boolean;
  /** Additional CSS classes */
  className?: string;
}

const StickyActionBar = React.forwardRef<HTMLDivElement, StickyActionBarProps>(
  (
    {
      leftContent,
      primaryAction,
      secondaryAction,
      visible = true,
      className,
    },
    ref
  ) => {
    if (!visible) {
      return null;
    }

    return (
      <div
        ref={ref}
        className={cn(
          'fixed bottom-0 left-0 right-0 z-50 md:hidden',
          'flex items-center gap-3 px-4 py-3',
          'bg-background/80 backdrop-blur-lg border-t border-border',
          'transition-transform duration-200',
          className
        )}
        style={{
          paddingBottom: 'calc(0.75rem + env(safe-area-inset-bottom, 0px))',
        }}
      >
        {leftContent && (
          <div className="flex-1 min-w-0 truncate text-sm text-muted-foreground">
            {leftContent}
          </div>
        )}
        <div className="flex items-center gap-2 shrink-0">
          {secondaryAction}
          {primaryAction}
        </div>
      </div>
    );
  }
);

StickyActionBar.displayName = 'StickyActionBar';

export { StickyActionBar, type StickyActionBarProps };
