'use client';

import {
  type ReactNode,
  type HTMLAttributes,
  useEffect,
} from 'react';
import { X } from 'lucide-react';

import { cn } from '../../utils';

export interface FullScreenSheetProps extends HTMLAttributes<HTMLDivElement> {
  /** Whether the sheet is open */
  open: boolean;
  /** Called when the sheet should close */
  onClose: () => void;
  /** Title displayed in the header */
  title: string;
  /** Optional actions to show in the header (right side) */
  headerActions?: ReactNode;
  /** Sheet content */
  children: ReactNode;
}

/**
 * FullScreenSheet component for mobile-optimized full-screen overlays.
 * Slides up from the bottom and covers the entire viewport.
 *
 * @example
 * ```tsx
 * const [open, setOpen] = useState(false);
 *
 * <Button onClick={() => setOpen(true)}>Open</Button>
 *
 * <FullScreenSheet
 *   open={open}
 *   onClose={() => setOpen(false)}
 *   title="Edit Item"
 *   headerActions={<Button size="sm">Save</Button>}
 * >
 *   <div className="p-4">
 *     <p>Your content here...</p>
 *   </div>
 * </FullScreenSheet>
 * ```
 */
const FullScreenSheet = ({
  open,
  onClose,
  title,
  headerActions,
  children,
  className,
  ...props
}: FullScreenSheetProps) => {
  // Handle escape key
  useEffect(() => {
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && open) {
        onClose();
      }
    };

    document.addEventListener('keydown', handleEscape);
    return () => document.removeEventListener('keydown', handleEscape);
  }, [open, onClose]);

  // Prevent body scroll when open
  useEffect(() => {
    if (open) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
    return () => {
      document.body.style.overflow = '';
    };
  }, [open]);

  if (!open) return null;

  return (
    <>
      {/* Backdrop */}
      <div
        data-slot="fullscreen-sheet-backdrop"
        className="fixed inset-0 z-50 bg-black/70 backdrop-blur-sm animate-in fade-in-0"
        onClick={onClose}
        aria-hidden="true"
      />

      {/* Sheet */}
      <div
        data-slot="fullscreen-sheet"
        role="dialog"
        aria-modal="true"
        aria-labelledby="fullscreen-sheet-title"
        className={cn(
          'fixed inset-0 z-50 flex flex-col bg-background',
          'animate-in slide-in-from-bottom duration-300',
          className
        )}
        {...props}
      >
        {/* Header */}
        <div
          data-slot="fullscreen-sheet-header"
          className="flex items-center justify-between border-b px-4 py-3"
        >
          <div className="flex items-center gap-3">
            <button
              type="button"
              onClick={onClose}
              className="rounded-sm p-1 opacity-70 ring-offset-background transition-opacity hover:opacity-100 focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2"
              aria-label="Close"
            >
              <X className="h-5 w-5" />
            </button>
            <h2
              id="fullscreen-sheet-title"
              className="text-lg font-semibold"
            >
              {title}
            </h2>
          </div>
          {headerActions && (
            <div data-slot="fullscreen-sheet-actions">
              {headerActions}
            </div>
          )}
        </div>

        {/* Content */}
        <div
          data-slot="fullscreen-sheet-content"
          className="flex-1 overflow-y-auto"
        >
          {children}
        </div>
      </div>
    </>
  );
};
FullScreenSheet.displayName = 'FullScreenSheet';

export interface FullScreenSheetContentProps extends HTMLAttributes<HTMLDivElement> {
  children: ReactNode;
}

/**
 * Content wrapper for FullScreenSheet with default padding.
 */
const FullScreenSheetContent = ({
  className,
  children,
  ...props
}: FullScreenSheetContentProps) => (
  <div
    data-slot="fullscreen-sheet-inner-content"
    className={cn('p-4', className)}
    {...props}
  >
    {children}
  </div>
);
FullScreenSheetContent.displayName = 'FullScreenSheetContent';

export { FullScreenSheet, FullScreenSheetContent };
