'use client';

import { forwardRef, memo, useMemo, type ComponentPropsWithoutRef } from 'react';

import { cn } from '../../utils';
import { StepCluster, type StepClusterStatus } from './step-cluster';

export interface StepState {
  status: StepClusterStatus;
  subTaskProgress: number; // 0-4
}

export interface StepConfig {
  /** Unique identifier for the step */
  id: string;
  /** Full label for the step */
  label: string;
  /** Short label for display */
  shortLabel: string;
  /** Category for grouping */
  category?: string;
  /** Order within the list (1-based) */
  order: number;
}

export interface StepProgressGridProps
  extends Omit<ComponentPropsWithoutRef<'div'>, 'children'> {
  /** Array of step configurations */
  steps: StepConfig[];
  /** Current step index (1-based), or 0 if not started */
  currentStep: number;
  /** Progress within current step (0-100) */
  stepProgress: number;
  /** Map of step states (for completed/error/skipped steps) */
  stepStates?: Record<string, StepState>;
  /** Show category headers above groups */
  showCategories?: boolean;
  /** Show step numbers below clusters */
  showNumbers?: boolean;
  /** Compact mode (no labels or headers) */
  compact?: boolean;
  /** Current step activity description */
  currentActivity?: string;
}

/**
 * Check for reduced motion preference
 */
function usePrefersReducedMotion(): boolean {
  if (typeof window === 'undefined') return false;
  return window.matchMedia?.('(prefers-reduced-motion: reduce)').matches ?? false;
}

/**
 * Get step status based on current step position and explicit states
 */
function getStepStatus(
  step: StepConfig,
  currentStep: number,
  stepStates?: Record<string, StepState>
): StepClusterStatus {
  // Check for explicit state (error, skipped, etc.)
  const explicitState = stepStates?.[step.id];
  if (explicitState?.status) {
    return explicitState.status;
  }

  // Derive status from current step
  if (step.order < currentStep) {
    return 'completed';
  } else if (step.order === currentStep) {
    return 'active';
  } else {
    return 'pending';
  }
}

/**
 * Get sub-task progress for a step
 */
function getSubTaskProgress(
  step: StepConfig,
  currentStep: number,
  stepProgress: number,
  stepStates?: Record<string, StepState>
): number {
  // Check for explicit state
  const explicitState = stepStates?.[step.id];
  if (explicitState?.subTaskProgress !== undefined) {
    return explicitState.subTaskProgress;
  }

  // Derive from progress
  if (step.order < currentStep) {
    return 4; // All complete
  } else if (step.order === currentStep) {
    // Convert 0-100 progress to 0-4 sub-tasks
    return Math.floor((stepProgress / 100) * 4);
  } else {
    return 0; // Not started
  }
}

/**
 * Calculate overall progress percentage
 */
function calculateOverallProgress(
  currentStep: number,
  stepProgress: number,
  totalSteps: number
): number {
  if (currentStep <= 0) return 0;
  if (currentStep > totalSteps) return 100;

  const completedSteps = currentStep - 1;
  const currentStepContribution = stepProgress / 100;
  return Math.round(((completedSteps + currentStepContribution) / totalSteps) * 100);
}

/**
 * Group steps by category
 */
function groupStepsByCategory(steps: StepConfig[]): Map<string, StepConfig[]> {
  const groups = new Map<string, StepConfig[]>();

  for (const step of steps) {
    const category = step.category || 'Steps';
    if (!groups.has(category)) {
      groups.set(category, []);
    }
    groups.get(category)!.push(step);
  }

  return groups;
}

/**
 * StepProgressGrid - Multi-step progress visualization with categories
 *
 * Displays a grid of StepClusters grouped by category, with overall
 * progress tracking and current step highlighting.
 *
 * @example
 * ```tsx
 * const steps = [
 *   { id: 'persona', label: 'Persona', shortLabel: 'Persona', category: 'Core Identity', order: 1 },
 *   { id: 'journey', label: 'Journey', shortLabel: 'Journey', category: 'Core Identity', order: 2 },
 *   { id: 'ia', label: 'Information Architecture', shortLabel: 'IA', category: 'Foundation', order: 3 },
 *   // ...
 * ];
 *
 * <StepProgressGrid
 *   steps={steps}
 *   currentStep={3}
 *   stepProgress={50}
 * />
 * ```
 */
const StepProgressGrid = forwardRef<HTMLDivElement, StepProgressGridProps>(
  (
    {
      steps,
      currentStep,
      stepProgress,
      stepStates,
      showCategories = true,
      showNumbers = false,
      compact = false,
      currentActivity,
      className,
      ...props
    },
    ref
  ) => {
    const prefersReducedMotion = usePrefersReducedMotion();
    const totalSteps = steps.length;
    const overallProgress = calculateOverallProgress(
      currentStep,
      stepProgress,
      totalSteps
    );

    // Get current step metadata
    const currentStepMeta = useMemo(() => {
      if (currentStep > 0 && currentStep <= totalSteps) {
        return steps.find((s) => s.order === currentStep) || null;
      }
      return null;
    }, [currentStep, steps, totalSteps]);

    // Group steps by category
    const categoryGroups = useMemo(
      () => groupStepsByCategory(steps),
      [steps]
    );

    // Reduced motion fallback: simple progress bar
    if (prefersReducedMotion && compact) {
      return (
        <div
          ref={ref}
          role="progressbar"
          aria-valuenow={overallProgress}
          aria-valuemin={0}
          aria-valuemax={100}
          aria-label={`Progress: ${overallProgress}% complete${currentStepMeta ? `, step ${currentStep} of ${totalSteps}: ${currentStepMeta.shortLabel}` : ''}`}
          className={cn('w-full', className)}
          {...props}
        >
          <div className="h-2 w-full overflow-hidden rounded-sm bg-muted/30">
            <div
              className="h-full bg-gradient-to-r from-orange-700 via-primary to-orange-400 transition-[width] duration-300"
              style={{ width: `${overallProgress}%` }}
            />
          </div>
        </div>
      );
    }

    return (
      <div
        ref={ref}
        role="progressbar"
        aria-valuenow={overallProgress}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-label={`Progress: ${overallProgress}% complete${currentStepMeta ? `, step ${currentStep} of ${totalSteps}: ${currentStepMeta.shortLabel}` : ''}`}
        className={cn('flex flex-col gap-2', className)}
        {...props}
      >
        {/* Category groups */}
        <div className="flex items-end gap-3">
          {Array.from(categoryGroups.entries()).map(([category, categorySteps]) => (
            <CategoryGroup
              key={category}
              category={category}
              steps={categorySteps}
              currentStep={currentStep}
              stepProgress={stepProgress}
              stepStates={stepStates}
              showHeader={showCategories && !compact}
              showNumbers={showNumbers}
            />
          ))}
        </div>

        {/* Current step label */}
        {!compact && currentStepMeta && currentStep > 0 && currentStep <= totalSteps && (
          <div className="flex items-center gap-2 text-sm">
            <span className="text-primary font-medium">
              Step {currentStep} of {totalSteps}:
            </span>
            <span className="text-foreground">{currentStepMeta.shortLabel}</span>
            {currentActivity && (
              <>
                <span className="text-muted-foreground">-</span>
                <span className="text-muted-foreground">{currentActivity}</span>
              </>
            )}
          </div>
        )}

        {/* Completion message */}
        {!compact && currentStep > totalSteps && (
          <div className="flex items-center gap-2 text-sm text-primary">
            <span className="font-medium">All steps complete</span>
          </div>
        )}
      </div>
    );
  }
);

StepProgressGrid.displayName = 'StepProgressGrid';

// Category Group Sub-component
interface CategoryGroupProps {
  category: string;
  steps: StepConfig[];
  currentStep: number;
  stepProgress: number;
  stepStates?: Record<string, StepState>;
  showHeader?: boolean;
  showNumbers?: boolean;
}

const CategoryGroup = memo(function CategoryGroup({
  category,
  steps,
  currentStep,
  stepProgress,
  stepStates,
  showHeader = true,
  showNumbers = false,
}: CategoryGroupProps) {
  return (
    <div className="flex flex-col gap-1">
      {/* Category header */}
      {showHeader && (
        <span className="text-[10px] font-medium uppercase tracking-wide text-muted-foreground">
          {category}
        </span>
      )}

      {/* Steps in this category */}
      <div className="flex items-center gap-1">
        {steps.map((step) => {
          const status = getStepStatus(step, currentStep, stepStates);
          const subTaskProgress = getSubTaskProgress(
            step,
            currentStep,
            stepProgress,
            stepStates
          );

          return (
            <StepCluster
              key={step.id}
              status={status}
              subTaskProgress={subTaskProgress}
              label={step.shortLabel}
              showNumber={showNumbers}
              stepNumber={step.order}
            />
          );
        })}
      </div>
    </div>
  );
});

export { StepProgressGrid };
