'use client';

import { forwardRef, useEffect, useState, type ComponentPropsWithoutRef } from 'react';
import { Check, Link2, AlertCircle, Ban, Loader2 } from 'lucide-react';

import { cn } from '../../utils';
import { ProgressBinStrip } from './progress-bin-strip';

export type RowStatus =
  | 'pending'
  | 'active'
  | 'completed'
  | 'error'
  | 'skipped'
  | 'linked';

export interface StakeholderProgressRowProps
  extends Omit<ComponentPropsWithoutRef<'div'>, 'children'> {
  /** Stakeholder role name */
  role: string;
  /** Index for color assignment */
  index: number;
  /** Current status of this stakeholder's generation */
  status: RowStatus;
  /** Number of completed bins (0-68) */
  completedBins: number;
  /** Total bins (default: 68) */
  totalBins?: number;
  /** Current step being processed (1-18), shown when active */
  currentStep?: number;
  /** Total steps (default: 18) */
  totalSteps?: number;
  /** Current step label */
  currentStepLabel?: string;
  /** Name of linked existing persona (for 'linked' status) */
  linkedPersonaName?: string;
  /** Callback for retry action */
  onRetry?: () => void;
  /** Callback for skip action */
  onSkip?: () => void;
  /** Custom icon component */
  icon?: React.ReactNode;
  /** Icon color (CSS color value) */
  iconColor?: string;
}

// Default color palette for stakeholder icons
const STAKEHOLDER_COLORS = [
  '#22c55e', // green
  '#3b82f6', // blue
  '#8b5cf6', // violet
  '#f59e0b', // amber
  '#ec4899', // pink
  '#06b6d4', // cyan
  '#ef4444', // red
  '#84cc16', // lime
];

function getColorForIndex(index: number): string {
  return STAKEHOLDER_COLORS[index % STAKEHOLDER_COLORS.length] ?? '#22c55e';
}

function getStatusLabel(
  status: RowStatus,
  completedBins: number,
  totalBins: number
): string {
  const percent = Math.round((completedBins / totalBins) * 100);
  switch (status) {
    case 'pending':
      return 'Waiting to start';
    case 'active':
      return `${percent}% complete, currently generating`;
    case 'completed':
      return 'Generation complete';
    case 'linked':
      return 'Linked to existing persona';
    case 'error':
      return `Error at ${percent}% complete`;
    case 'skipped':
      return 'Skipped';
  }
}

/**
 * StakeholderProgressRow - Single stakeholder with progress strip
 *
 * Layout: [Icon + Name (180px)] [Progress Strip (flex)] [Status Badge]
 *
 * @example
 * ```tsx
 * // Completed row
 * <StakeholderProgressRow
 *   role="Product Manager"
 *   index={0}
 *   status="completed"
 *   completedBins={68}
 * />
 *
 * // Active row with current step
 * <StakeholderProgressRow
 *   role="Engineering Lead"
 *   index={1}
 *   status="active"
 *   completedBins={42}
 *   currentStep={11}
 *   currentStepLabel="KPIs"
 * />
 *
 * // Error row with retry/skip
 * <StakeholderProgressRow
 *   role="Data Analyst"
 *   index={3}
 *   status="error"
 *   completedBins={20}
 *   onRetry={() => handleRetry()}
 *   onSkip={() => handleSkip()}
 * />
 * ```
 */
const StakeholderProgressRow = forwardRef<
  HTMLDivElement,
  StakeholderProgressRowProps
>(
  (
    {
      role,
      index,
      status,
      completedBins,
      totalBins = 68,
      currentStep,
      totalSteps = 18,
      currentStepLabel,
      linkedPersonaName,
      onRetry,
      onSkip,
      icon,
      iconColor,
      className,
      ...props
    },
    ref
  ) => {
    const [showCompleteFlash, setShowCompleteFlash] = useState(false);

    // Trigger completion flash animation
    useEffect(() => {
      if (status === 'completed') {
        setShowCompleteFlash(true);
        const timer = setTimeout(() => setShowCompleteFlash(false), 400);
        return () => clearTimeout(timer);
      }
      return undefined;
    }, [status]);

    const isActive = status === 'active';
    const isCompleted = status === 'completed';
    const isPending = status === 'pending';
    const isError = status === 'error';
    const isSkipped = status === 'skipped';
    const isLinked = status === 'linked';

    const color = iconColor || getColorForIndex(index);

    return (
      <div
        ref={ref}
        className={cn(
          'flex items-center gap-3 py-3 px-4 transition-all duration-200',
          // Active row styling
          isActive && 'bg-primary/5',
          // Completion flash
          showCompleteFlash && 'animate-row-flash',
          // Pending row is dimmed
          isPending && 'opacity-50',
          // Error row border
          isError && 'border-l-2 border-destructive',
          className
        )}
        role="group"
        aria-label={`${role}: ${getStatusLabel(status, completedBins, totalBins)}`}
        {...props}
      >
        {/* Icon + Name */}
        <div className="flex items-center gap-2 w-[180px] flex-shrink-0">
          <div
            className={cn(
              'flex h-8 w-8 items-center justify-center rounded-full',
              isPending ? 'bg-muted/30' : 'bg-opacity-20',
              isLinked && 'bg-blue-500/10'
            )}
            style={{
              backgroundColor:
                isPending || isLinked ? undefined : `${color}20`,
            }}
          >
            {icon ? (
              icon
            ) : isCompleted ? (
              <Check className="h-4 w-4 text-primary" />
            ) : isLinked ? (
              <Link2 className="h-4 w-4 text-blue-500" />
            ) : isError ? (
              <AlertCircle className="h-4 w-4 text-destructive" />
            ) : isSkipped ? (
              <Ban className="h-4 w-4 text-muted-foreground" />
            ) : isActive ? (
              <Loader2 className="h-4 w-4 text-primary animate-spin" />
            ) : (
              <span
                className="text-xs font-medium"
                style={{ color: isPending ? undefined : color }}
              >
                {role
                  .split(' ')
                  .map((w) => w[0])
                  .join('')
                  .slice(0, 2)}
              </span>
            )}
          </div>
          <span
            className={cn(
              'text-sm font-medium truncate',
              isPending && 'text-muted-foreground',
              isCompleted && 'text-muted-foreground',
              isLinked && 'text-muted-foreground',
              isError && 'text-destructive'
            )}
          >
            {role}
          </span>
        </div>

        {/* Progress Strip */}
        <div className="flex-1 min-w-0">
          <ProgressBinStrip
            totalBins={totalBins}
            completedBins={completedBins}
            isActive={isActive}
            isComplete={isCompleted || isLinked}
            hasError={isError}
            isLinked={isLinked}
          />
        </div>

        {/* Status / Actions */}
        <div className="w-[140px] flex-shrink-0 text-right">
          {isActive && currentStep && (
            <span className="text-xs text-primary font-medium">
              Step {currentStep}/{totalSteps}
              {currentStepLabel && (
                <span className="text-muted-foreground font-normal ml-1">
                  {currentStepLabel}
                </span>
              )}
            </span>
          )}
          {isPending && (
            <span className="text-xs text-muted-foreground">Waiting...</span>
          )}
          {isCompleted && (
            <span className="text-xs text-primary font-medium flex items-center justify-end gap-1">
              <Check className="h-3 w-3" />
              Complete
            </span>
          )}
          {isLinked && (
            <span className="text-xs text-blue-500 font-medium flex items-center justify-end gap-1">
              <Link2 className="h-3 w-3" />
              {linkedPersonaName ? `Linked to ${linkedPersonaName}` : 'Existing persona'}
            </span>
          )}
          {isSkipped && (
            <span className="text-xs text-muted-foreground">Skipped</span>
          )}
          {isError && (
            <div className="flex items-center justify-end gap-2">
              {onRetry && (
                <button
                  onClick={onRetry}
                  className="text-xs text-primary hover:underline"
                >
                  Retry
                </button>
              )}
              {onSkip && (
                <button
                  onClick={onSkip}
                  className="text-xs text-muted-foreground hover:underline"
                >
                  Skip
                </button>
              )}
            </div>
          )}
        </div>
      </div>
    );
  }
);

StakeholderProgressRow.displayName = 'StakeholderProgressRow';

export { StakeholderProgressRow };
